/* English content generated from lessons.js (natural-English translation pass).
   Keyed by day; renderer (zhen/ENL) falls back to Chinese for any missing field. */
window.EN = {"1": {"themeEn": "The First Step — Introducing Yourself and Daily Life", "goalsEn": ["Solidify the は/が and です・ます systems", "Master 〜ています for ongoing actions and habits", "Learn 〜てから, 〜のは…です, and 〜たい"], "paraEn": ["Nice to meet you. I'm a student. I came from China.", "Right now, I'm studying Japanese.", "Every morning I get up at six, and after washing my face I eat breakfast.", "Then I take the train and go to school. Classes start at nine.", "My Japanese still isn't very good, but I practice a little bit every day.", "Memorizing new words is hard work, but it's a lot of fun.", "I understand what the kanji mean, but their readings are difficult.", "So I keep up the practice of reading aloud.", "A year from now, I want to be able to talk freely with Japanese friends. That's what I'm working hard for now."], "vocabEn": {"自己紹介": "self-introduction", "毎朝": "every morning", "顔を洗う": "to wash one's face (顔 'face' + を + 洗う 'to wash')", "電車に乗る": "to take/ride a train (note: 乗る takes the particle に)", "授業": "class, lesson", "始まる": "to begin, to start (intransitive; cf. transitive 始める)", "上手": "skilled, good at (na-adjective)", "少しずつ": "little by little, bit by bit", "覚える": "to memorize, to learn by heart (transitive, Group II)", "大変": "tough, difficult; (as an adverb) very, extremely", "読み方": "way of reading, how to read it (〜方 = 'the way of doing ~')", "声に出す": "to say out loud, to voice", "続ける": "to continue, to keep up (transitive; cf. intransitive 続く)", "自由に": "freely (from the na-adjective 自由)", "頑張る": "to do one's best, to try hard (intransitive, Group I)"}, "gramEn": {"〜から（来ました）": {"exp": "The particle から marks a source or starting point: 'from.' 中国から来ました = 'I came from China.' Don't confuse this with the から that means 'because,' which attaches to a full clause rather than a noun.", "ex": ["In Japan it's been raining since the morning.", "I walk from the station to my house. (から…まで = 'from … to …')"]}, "〜ています": {"exp": "Formed from the te-form of a verb plus います, this has two core uses: (1) an action in progress (今、勉強しています = 'I'm studying right now'), and (2) an ongoing habit or state (練習しています = 'I keep practicing'). Note that 住んでいます uses で, not て: 住む ends in む, so its te-form undergoes a sound change to 住んで (verbs ending in ぬ/ぶ/む become 〜んで). Most shifts in conjugation or pronunciation come from these regular euonic (onbin) changes — see the Basics section on verb conjugation.", "ex": ["My older sister lives in Tokyo. (an ongoing state)", "I write in my diary every day. (a habit)"]}, "V-てから": {"exp": "Verb te-form + から means 'after doing A, (then) do B,' emphasizing the order of events: first A, then B. 顔を洗ってから朝ご飯を食べます = 'After washing my face, I eat breakfast.'", "ex": ["After I finish my homework, I go to sleep.", "Please wash your hands before you eat."]}, "〜のは〜です": {"exp": "の turns a verb or clause into a noun phrase so it can act as the subject or object of a sentence. 新しい言葉を覚えるのは大変です = 'Memorizing new words is hard.' Here の packages the whole action up into a single 'thing.'", "ex": ["Speaking Japanese is fun.", "Getting up early is hard."]}, "V-たい / 〜ために": {"exp": "Verb stem (ます-form) + たい means 'want to do …' (話せる → 話したい, 'want to be able to speak'). そのために means 'for that purpose, to that end,' picking up the goal stated in the previous sentence.", "ex": ["I want to work in Japan.", "For my health, I walk every day."]}}, "convEn": ["A: What do you do for work? B: I'm a student. I'm studying Japanese.", "A: Your Japanese is really good. B: No, no, I've still got a long way to go. I'm working at it bit by bit. (まだまだです is a natural, modest way to deflect a compliment.)", "A: What time do you get up in the morning? B: I get up at six and wash my face right away."], "extEn": ["勉強する ≈ 学ぶ ≈ 習う: 勉強する = 'to study' (broad sense); 学ぶ = 'to learn/acquire knowledge or principles' (somewhat formal/literary); 習う = 'to learn a skill from a teacher.'", "Saying you're 'good/bad at' something: 上手 (じょうず) ↔ 下手 (へた) judge someone else's skill; 得意 (とくい) ↔ 苦手 (にがて) describe what you yourself are good at or weak at, which sounds more natural. When talking about yourself, prefer 得意・苦手.", "Words related to 頑張る: 頑張ってください = 'Good luck / hang in there'; 頑張ります = 'I'll do my best'; お疲れさま = 'Thanks for your hard work / good job' (extremely common in daily life)."], "reflectEn": ["In today's text, which kanji readings did you not know before? Copy them out in kana three times each.", "Make a sentence describing your own morning using 〜てから.", "「漢字の意味は分かりますが、読み方が難しいです」 — this is exactly your situation. Try reading the whole passage aloud once without looking at the kana."]}, "2": {"themeEn": "Hobbies and Habits — Learning Through What You Love", "goalsEn": ["Master 〜ようになる to express change ('came to be able to / started doing')", "Master 〜たり〜たりする for listing actions", "Master 〜ながら ('while') and 〜と思う for stating opinions"], "paraEn": ["My hobby is listening to music. Ever since I was a child, I've loved to sing.", "On weekends, I play the guitar at home and watch movies I like, and so on.", "Lately, I've started listening to Japanese songs a lot, too.", "When I look up what the lyrics mean, I can pick up new words naturally.", "While listening to songs, I also practice my pronunciation.", "I used to not be able to catch fast Japanese at all, but after keeping it up every day, I've gradually come to understand a little.", "I think that when you study through something you love, it's fun and you can keep it up for a long time.", "So from now on, too, I want to keep learning Japanese together with music."], "vocabEn": {"趣味": "hobby, interest", "〜の頃": "around the time of ~ (子どもの頃 = 'when I was a child')", "週末": "weekend", "弾く": "to play (a string/keyboard instrument)", "映画": "movie, film", "最近": "recently, lately", "歌詞": "lyrics", "調べる": "to look up, to investigate", "自然に": "naturally", "発音": "pronunciation", "速い": "fast (in speed)", "聞き取る": "to catch / make out (by ear), to comprehend by listening", "全く〜ない": "not … at all (paired with a negative)", "〜を通して": "through, by means of", "学ぶ": "to learn (somewhat literary)"}, "gramEn": {"〜ようになる": {"exp": "Expresses a change — 'to come to / to get to the point where …' — stressing the shift from 'didn't/couldn't before' to 'do/can now.' It's often used with the potential form: 聞き取れるようになりました = 'I've come to be able to catch (it).' This is the key pattern from N4 into N3 for describing your own progress, which fits your situation perfectly.", "ex": ["After practicing, I came to be able to swim.", "I've started eating vegetables (when I didn't before)."]}, "〜たり〜たりする": {"exp": "Lists a few representative actions (not an exhaustive list): 弾いたり、見たりします = 'I do things like play the guitar and watch movies.' Formed with the verb ta-form + り. It conveys 'and the like / among other things' more naturally than 〜て、〜て.", "ex": ["On my days off I do things like read books and take walks."]}, "V-ながら": {"exp": "Verb stem (ます-form) + ながら means 'while doing A, (do B)' — two actions at the same time by one person. The main action goes in the second clause: in 聞きながら練習する, the focus is on 'practicing.'", "ex": ["I study while listening to music.", "Looking at your phone while walking is dangerous."]}, "〜し、〜 / 〜と思う": {"exp": "〜し lists reasons or qualities ('and what's more …, plus …'), with a nuance of piling them up: 楽しいし、続けられる = 'it's fun, and on top of that you can keep it up.' 〜と思う means 'I think / I believe' — the basic pattern for stating a personal opinion, and extremely common in speech.", "ex": ["This shop is cheap, and the food's good too.", "I think it'll be sunny tomorrow."]}}, "convEn": ["A: What are your hobbies? B: Music. Lately I've started listening to Japanese songs.", "A: Can you catch spoken Japanese? B: It's still hard when it's fast, but I've gradually come to understand a little.", "A: What do you do on weekends? B: I watch movies, play the guitar, things like that."], "extEn": ["'To like doing something': 〜のが好き (好き + the nominalizer の). For 'to be good at it,' use 〜のが得意 (とくい).", "〜ようになる vs. 〜ことにする: the former is a natural change ('come to be able to …'); the latter is a personal decision ('decide to …'). You'll meet the decision-type patterns in Day 3.", "Listening-related verbs: 聞く (to listen) → 聞こえる (to hear / be audible, happening on its own) → 聞き取る (to make out by listening effort). Three different levels."], "reflectEn": ["Write one sentence about your own progress in learning Japanese using 〜ようになりました.", "Imitate the text's 〜たり〜たり and 〜ながら, writing one sentence each about your own weekend.", "Read this passage aloud to a family member without looking at the kana; note the words you stumble on and focus on shadowing the audio for them tomorrow morning."]}, "3": {"themeEn": "My Study Method — The Knack of Keeping It Up", "goalsEn": ["Master obligation 〜なければならない and advice 〜たほうがいい", "Review the potential form (話せる, 覚えられる)", "Master intention 〜つもり and wrap up goals with 〜ようになる"], "paraEn": ["When I study Japanese, there are a few methods I really value.", "First, sitting down at my desk at the same time every day. Even a short stretch is fine, but I have to keep it up.", "Second, I read the passages I want to memorize out loud, over and over.", "Rather than only writing, saying things out loud helps me remember them better.", "Then, I use the grammar I've learned to try making my own short sentences.", "I don't worry if I make mistakes. That's because you can learn from your mistakes.", "Passing the exam matters too, but my real goal is to become able to express my own thoughts freely.", "For that, I intend to keep moving forward one step at a time from here on."], "vocabEn": {"方法": "method, way", "大切にする": "to value, to cherish, to treat as important", "机に向かう": "to sit down at one's desk (to study/work) (机 'desk' + に + 向かう 'to face')", "短い": "short", "何回も": "many times, over and over", "口に出す": "to say out loud, to put into words", "習う": "to learn (from someone), to take lessons in", "文法": "grammar", "間違える": "to make a mistake, to get wrong (transitive; cf. 間違う)", "気にする": "to mind, to worry about, to let something bother you", "試験": "exam, test", "合格する": "to pass (an exam)", "目標": "goal, objective", "考え": "thought, idea, opinion", "一歩ずつ": "step by step, one step at a time"}, "gramEn": {"〜なければならない / 〜なきゃ": {"exp": "Expresses obligation — 'must, have to.' Formed by taking the verb's ない-form, dropping the い, and adding ければならない (続ける → 続けなければならない). In casual speech this is often shortened to 〜なきゃ(いけない). In writing, 〜なければならない is standard.", "ex": ["I have to hand it in by tomorrow.", "I gotta go now. (casual)"]}, "〜たほうがいい": {"exp": "Gives advice: verb ta-form + ほうがいい = 'you'd better / it's better to do …' For negative advice, use 〜ないほうがいい. In the text, 口に出したほうがよく覚えられます = 'saying it out loud helps you remember it better.'", "ex": ["You'd better go to sleep early.", "You'd better not overdo it."]}, "可能形 / 〜ことができる": {"exp": "Two ways to say 'can': (1) the potential form (話す → 話せる, 覚える → 覚えられる, する → できる); and (2) the dictionary form + ことができる (more formal/written). Both appear in the text: 覚えられます and 学ぶことができる.", "ex": ["I've become able to read kanji. (potential form + ようになる)", "You can take photos here."]}, "〜つもり": {"exp": "Expresses a subjective intention: dictionary form + つもりです = 'I intend / plan to do …' It's more deliberate than 〜たい ('want to') but more personal than 〜予定 (a fixed, scheduled arrangement). In the text, 進んでいくつもりです = 'I intend to keep moving forward.'", "ex": ["I intend to take the N2 next year.", "I plan to do nothing at all today."]}}, "convEn": ["A: How do you study Japanese? B: I make a point of reading aloud every day. (〜ようにしている = 'make a point of / try to keep up the habit of')", "A: I'm scared of making mistakes. B: It's fine. You can learn from your mistakes, you know.", "A: What do you intend to do from here? B: I intend to keep it up, one step at a time."], "extEn": ["Strength of obligation expressions: 〜なければならない / 〜ないといけない ('must') > 〜べきだ ('should,' with a sense of moral/logical judgment) > 〜たほうがいい ('had better,' advice).", "The intention trio: 〜たい (want to — emotional) → 〜つもり (intend to — subjective plan) → 〜予定 (よてい) (scheduled — an objective arrangement).", "〜ようにする (to make an effort to keep up a habit) vs. 〜ようになる (a natural change): する = I actively do it; なる = it ends up becoming so. Both show up across Day 2 and Day 3 — be sure to keep them straight."], "reflectEn": ["Tonight, use 〜つもり to write down one concrete plan for these 30 days.", "Look back over Days 1–3: you've already learned は/が, 〜ています, 〜てから, 〜ようになる, 〜なければならない, the potential form, and 〜つもり. Pick two and make sentences.", "Copy out the whole passage once (first check the kana in Type mode, then write it from memory in Hide mode). Tomorrow you move on to Day 4."]}, "4": {"themeEn": "My Town — Places and Existence", "goalsEn": ["Master 〜に〜があります／います and ある・いる", "Position nouns (近く, 横, 中, 間)", "Describe a place using adjectives"], "paraEn": ["The town I live in is a very quiet place.", "There's a small park near the station, and right beside it is an old library.", "Inside the park there are lots of big trees.", "When morning comes, there are people walking their dogs and people out jogging.", "It's about a ten-minute walk from my house to the station, so it's very convenient.", "There's a supermarket and a convenience store nearby too, so I never have any trouble with daily life.", "It's just that the shops close early at night, so sometimes it's a little inconvenient.", "Even so, I love this quiet town.", "Someday, once my Japanese gets better, I'd like to talk more with my neighbors."], "vocabEn": {"住む": "to live, to reside (住んでいる = 'is living/resides')", "静か": "quiet (na-adjective)", "所": "place", "近く": "vicinity, nearby area", "公園": "park", "横": "side, beside", "古い": "old (of things, not people)", "図書館": "library", "散歩する": "to take a walk, to go for a stroll", "便利": "convenient (na-adjective; ↔ 不便 ふべん, 'inconvenient')", "生活": "daily life, living", "困る": "to be in trouble, to be at a loss, to have difficulty", "閉まる": "to close, to shut (intransitive; cf. 開く あく 'to open,' 閉める 'to close [trans.]')", "近所": "neighborhood, the local area"}, "gramEn": {"〜に〜があります / います": {"exp": "Expresses existence — 'there is/are.' The location is marked with に; use ある for inanimate things and いる for animate ones (people and animals). 公園に木があります ('there are trees in the park'), 公園に人がいます ('there are people in the park'). This is the foundation for describing places.", "ex": ["There's a book on the desk.", "There's a cat in the room."]}, "位置名词（〜の近く・横・中・間）": {"exp": "Use 'noun + の + position word' to express relative location: 近く (nearby), 横 / となり (beside, next to), 中 (inside), 上/下 (above/below), 前/後ろ (in front of/behind), 間 (あいだ, between). For example, 駅の近くに ('near the station'), 公園の中に ('inside the park').", "ex": ["The bank is next to the convenience store.", "There's a bookshop between the station and the school."]}, "〜になると": {"exp": "Noun + になると means 'when it becomes (a certain time/state), then …,' describing a natural, regular result. 朝になると人が増える = 'when morning comes, the number of people increases.'", "ex": ["When winter comes, it snows.", "When spring comes, the cherry blossoms bloom."]}, "〜し、〜（理由の列挙）": {"exp": "Use 〜し to list several reasons, with an 'and what's more' nuance, often leading to a conclusion. スーパーもあるし、便利だ = 'there's a supermarket too, (so) it's convenient.'", "ex": ["The station's close, and it's quiet — it's a nice town."]}}, "convEn": ["A: Where do you live? B: Near the station. It's a nice, quiet place.", "A: Is there a convenience store nearby? B: Yes, there's one right over there.", "A: It's a nice town, isn't it. B: Yeah, it's convenient for daily life, and I really like it. (気に入る = 'to take a liking to')"], "extEn": ["ある vs. いる: use ある for things and plants; use いる for people and animals. Possession ('to have') also uses ある: お金がある ('to have money').", "Quick reference for position words: 上 (うえ, above) / 下 (した, below) / 前 (まえ, in front) / 後ろ (うしろ, behind) / 中 (なか, inside) / 外 (そと, outside) / 隣 (となり, next to) / 間 (あいだ, between) / 近く (ちかく, near).", "Na-adjectives for describing places: 静か ↔ 賑やか (にぎやか, lively), 便利 ↔ 不便, きれい (clean/pretty), 安全 (あんぜん, safe). Note that 十分 = じゅっぷん has both a geminate (small っ) and a long vowel — easy to misread."], "reflectEn": ["Use 〜に〜があります／います to describe two things near your home (one with ある, one with いる).", "Imitate 朝になると… to write one sentence about a scene you see in the morning.", "Cover the kana and read aloud, paying special attention to the readings of 十分 (じゅっぷん) and 図書館 (としょかん)."]}, "5": {"themeEn": "Memories — Talking About an Experience", "goalsEn": ["Master 〜たことがある to express experience", "Tense changes before 〜とき", "Narrate coherently in the past tense"], "paraEn": ["Last summer, I went on a trip by myself for the first time.", "Ever since I was little, I'd always wanted to go see all kinds of places.", "I took the train and traveled to a town near the sea.", "When I arrived in that town, the sky was beautiful and the breeze felt wonderful.", "Up until then, I had never seen such a vast ocean.", "Chatting with the locals, I ate delicious fish dishes.", "There were times when we couldn't communicate very well, but everyone was kind.", "Through that trip, I discovered the joy of talking with strangers.", "This experience is a memory I'll never forget for as long as I live."], "vocabEn": {"去年": "last year", "初めて": "for the first time", "一人で": "alone, by oneself", "〜とき": "when …, at the time of …", "着く": "to arrive", "空": "sky", "風": "wind, breeze", "広い": "wide, spacious, vast (↔ 狭い せまい, 'narrow')", "地元": "the local area, one's hometown area", "通じる": "to get through, to communicate (言葉が通じる = 'to make oneself understood')", "親切": "kind, considerate (na-adjective)", "〜を通して": "through, by way of (通す とおす ≠ 通じる つうじる — same kanji, different readings)", "経験": "experience", "忘れる": "to forget (忘れられない = 'unforgettable')", "思い出": "memory, recollection"}, "gramEn": {"〜たことがある / ない": {"exp": "Verb ta-form + ことがある means 'have (ever) done …,' stressing whether or not you have that experience. 海を見たことがない = 'I've never seen the sea.' This differs from a plain past tense like 見た, which just states that the action happened.", "ex": ["I've made Japanese food before.", "I've never climbed Mt. Fuji."]}, "〜とき（時制に注意）": {"exp": "The tense before とき determines the point in time: 着いたとき (after arriving / the moment of arrival) vs. 着くとき (before arriving / as I'm about to arrive). Use the ta-form for a completed action and the dictionary form for one not yet completed.", "ex": ["Before going to Japan (as I was setting off), I bought a dictionary.", "When I got to Japan (after arriving), I bought a dictionary."]}, "〜にとって": {"exp": "Noun + にとって means 'for / to (someone),' giving an evaluation from that person's point of view. 私にとって大切な思い出 = 'a memory that's precious to me.'", "ex": ["This is a special day for me."]}, "形容词・动词 ＋ さ": {"exp": "Drop the い from an i-adjective (or attach to a na-adjective) and add さ to turn a quality into a noun: 楽しい → 楽しさ ('fun, enjoyment'), 広い → 広さ ('width, extent'), 便利 → 便利さ ('convenience').", "ex": ["This mountain's height is three thousand meters.", "I've started to understand the joy of studying."]}}, "convEn": ["A: Have you ever been to Japan? B: Yes, just once.", "A: How was the trip? B: Everyone was kind — it turned into a wonderful memory.", "A: Isn't it scary, traveling alone? B: I was anxious at first, but once I got used to it, it was fun."], "extEn": ["The same kanji 通 has different readings: 通じる (つうじる, to communicate / be understood) ↔ 通す・通して (とおす, to pass through / by way of). The meaning is related through the character, but there are two separate readings — exactly the kind of thing you need to focus on memorizing.", "〜たことがある (experience) ≠ 〜ている (state) ≠ 〜た (a simple completed action). To ask whether someone has 'ever experienced' something, you must use ことがある.", "The 'さ' nominalizing family: 高さ (height), 長さ (length), 重さ (おもさ, weight), 大きさ (おおきさ, size), 楽しさ (fun), 便利さ (convenience), 親切さ (kindness). It expresses a degree or property and is very common in writing."], "reflectEn": ["Use 〜たことがあります／ありません to write one sentence each about something you have done and something you haven't.", "Take a single verb and pair it with both the dictionary form and the ta-form before とき, making two sentences to feel the difference in tense.", "Write the last sentence from memory (about the unforgettable, lifelong memory), watching the geminate/long vowel in 一生 (いっしょう)."]}, "11": {"themeEn": "Hearsay and Conjecture — \"I hear that,\" \"it looks like,\" \"it seems\"", "goalsEn": ["Tell apart 「降るそうだ」(I hear it'll rain) from 「降りそうだ」(it's about to rain)", "Compare degrees of certainty: らしい / ようだ / みたい", "Use 「〜によると」to cite where information comes from"], "paraEn": ["According to the weather forecast, it's going to rain tomorrow.", "Looking up at the sky, clouds that seem about to drop rain any moment are spreading out.", "According to a friend, this year's exam is apparently going to get a bit harder.", "He seems to be studying at the library every day lately.", "From the look on his face, he seemed pretty tired.", "I'm starting to get the feeling that, at this rate, I won't make it in time either.", "Rumor has it the exam format will change starting next year, but I have no idea whether it's true.", "There's so much information that I get confused about what to believe.", "It's precisely at times like this, I think, that you should trust your own plan and press forward."], "vocabEn": {"天気予報": "weather forecast", "〜によると": "according to", "降る": "to fall (rain/snow)", "雲": "cloud", "疲れる": "to get tired", "間に合う": "to make it in time", "気がする": "to have a feeling", "噂": "rumor", "形式": "format, form", "情報": "information", "信じる": "to believe", "迷う": "to be unsure, to get lost"}, "gramEn": {"〜そうだ（伝聞）": {"exp": "Reports information you heard from somewhere else (\"I hear that…,\" \"They say…\"). It attaches to the plain (dictionary) form of the clause: 降る／降った／難しい／学生だ ＋ そうだ. It often pairs with source phrases like 〜によると, 〜の話では, or 噂では.", "ex": ["According to the news, there was an earthquake."]}, "〜そうだ（様態）": {"exp": "Expresses a judgment based on how something looks right now (\"it looks like…,\" \"it's about to…\"). It attaches to a verb's ます-stem (drop ます) or to an adjective stem: 降り＋そう, 難し＋そう, よさそう. So 「今にも降りそうだ」 means \"it looks like it'll rain any second.\" The negative is 降りそうにない.", "ex": ["This cake looks delicious!", "The button looks like it's about to come off."]}, "〜らしい": {"exp": "A guess based on something you heard or on objective signs — \"it seems / apparently.\" It carries a touch more of the speaker's own judgment than the hearsay そうだ. It can also mean \"typical of / behaving as one should\": 男らしい (manly).", "ex": ["That shop seems to have already closed down."]}, "〜ようだ / 〜みたい": {"exp": "A guess drawn from your own observation or impression, with a fairly high degree of confidence. 「みたい」 is the casual, spoken version of 「ようだ」: 疲れているようだ／みたい. It can also express a likeness or metaphor: 「夢のようだ」(like a dream).", "ex": ["It seems cold outside — the window has frozen over."]}}, "convEn": ["A: I hear it's going to rain tomorrow. B: Oh, really? I'll bring an umbrella.", "A: He's seemed busy lately, hasn't he? B: Yeah, looks like his exam is coming up.", "A: Apparently this place is good. B: Then shall we go give it a try?"], "extEn": ["Hearsay vs. appearance (most important): 「降るそうだ」 (dictionary form + そうだ = I hear it'll rain) ↔ 「降りそうだ」 (ます-stem + そうだ = it looks about to rain). A single difference in what it attaches to flips the meaning entirely.", "Rough ranking of certainty: ようだ/みたい (seen with your own eyes, fairly sure) ≈ らしい (heard, objective) > そうだ (hearsay, just relaying — no responsibility taken).", "「〜によると／〜の話では／噂では」 specifically introduce a source and pair almost exclusively with the hearsay 「そうだ」."], "reflectEn": ["Write one sentence each with 「降るそうだ」 and 「降りそうだ」 to confirm you can distinguish \"I hear\" from \"about to.\"", "Use 「らしい・ようだ・みたい」 to describe the recent state of someone around you.", "Write from memory the sentence about \"so much information, what to believe.\""]}, "12": {"themeEn": "Basics of Keigo — A First Formal Introduction", "goalsEn": ["Use humble language to lower yourself (参る・申す・拝見)", "Use respectful language to elevate the other person (いらっしゃる・ご覧になる)", "Master high-frequency set phrases for business"], "paraEn": ["Thank you for taking the time to see me today, despite how busy you are.", "I come from China; my name is Wang.", "I have been studying Japanese for two years, and I am now aiming to pass the N2.", "The other day I looked at your company's website, and I knew I would really love to work here.", "If I could work alongside the people here in Japan, I would be truly delighted.", "If there is anything you don't understand, please don't hesitate to tell me.", "If there is anything I can do to be of help, I will do whatever is needed.", "Today, I look forward to working with you. Thank you very much."], "vocabEn": {"本日": "today (formal)", "参る": "to come/go (humble)", "申す": "to say (humble)", "〜ており": "-ing (humble/formal form of 〜ている)", "目指す": "to aim for", "御社": "your company", "拝見する": "to see, to read (humble)", "方": "person (polite)", "存じる": "to think / to know (humble)", "おっしゃる": "to say (respectful)", "いたす": "to do (humble)", "お願いいたします": "please / I humbly ask you"}, "gramEn": {"謙譲語（压低自己）": {"exp": "Humble language is used when describing your own actions, so as to raise the other person up by comparison. Common verbs: 参る (for 行く/来る), 申す (言う), 拝見する (見る), おる (いる), いたす (する), 存じる (思う/知る), いただく (もらう). The general pattern is 「お ＋ ます-stem ＋ する」.", "ex": ["I will show you the way. (お〜いたす)"]}, "尊敬語（抬高对方）": {"exp": "Respectful language is used when describing the other person's actions. Common verbs: いらっしゃる (行く/来る/いる), おっしゃる (言う), ご覧になる (見る), なさる (する), 召し上がる (食べる). The general patterns are 「お ＋ ます-stem ＋ になる」 and 「〜れる／られる」.", "ex": ["The president has already gone home. (〜られる, respectful)", "What would you like to eat?"]}, "丁寧語・美化語": {"exp": "です／ます／ございます are polite (teineigo) forms; お／ご attached to nouns (お時間, 御社, お仕事, ご案内) is beautifying/respectful. 「ございます」 is the formal form of 「ある」.", "ex": ["The materials are right here."]}, "いただく / くださる": {"exp": "When you receive a favor, use いただく (〜ていただく = \"have someone kindly do…\" / \"I am favored with…\"). When the other person gives to you, use くださる (〜てくださる). 「教えていただく」 ≈ 「教えてくださる」 — the difference is just the point of view.", "ex": ["I had my teacher kindly teach me."]}}, "convEn": ["A: Is the president in? B: He has just stepped away from his desk at the moment. (席を外す = to step away from one's seat)", "A: May I take a look at the materials? B: Yes, please go ahead and have a look.", "A: What would you like to have? B: I'll have a coffee."], "extEn": ["Mnemonic: respectful language raises others (いらっしゃる・なさる・召し上がる・おっしゃる・ご覧になる); humble language lowers yourself (参る・いたす・申す・拝見する・いただく). Never use respectful forms for your own actions.", "Comparison table: 見る → ご覧になる／拝見する; 言う → おっしゃる／申す; する → なさる／いたす; いる → いらっしゃる／おる; 食べる・飲む → 召し上がる／いただく.", "All-purpose business phrases: お世話になっております・恐れ入りますが・よろしくお願いいたします・承知いたしました."], "reflectEn": ["Write out both the respectful and the humble forms of 「行く・見る・する」.", "Following the model passage, write your own opening keigo line (a self-introduction).", "Write 「本日はどうぞよろしくお願いいたします」 from memory and point out the keigo elements in it."]}, "13": {"themeEn": "A Story — The Ant and the Grasshopper", "goalsEn": ["The quotative 「と」 (〜と言いました)", "「〜てばかりいる」: always doing nothing but…", "The advisory 「〜なさい」 and 「〜てしまう」"], "paraEn": ["Once upon a time, there was a hardworking ant and a grasshopper who did nothing but sing.", "Through the hot summer, the ants diligently carried food for the winter.", "Watching this, the grasshopper laughed and said, \"Working that hard — is it fun?\"", "\"There's so much food right now,\" it said, \"so why on earth are you working?\"", "The ant answered, \"When winter comes, there'll be nothing left to eat.\"", "But the grasshopper wouldn't listen, and did nothing but play day after day.", "Before long the cold winter arrived, and the grass in the fields had completely withered away.", "With no food left, the grasshopper finally realized its mistake.", "\"Preparedness prevents misfortune\" — the lesson is: don't just enjoy the present; think about what lies ahead, too."], "vocabEn": {"働く": "to work", "〜ばかり": "only, nothing but", "間": "during, between", "運ぶ": "to carry", "笑う": "to laugh", "答える": "to answer", "遊ぶ": "to play", "やがて": "before long", "野原": "field", "枯れる": "to wither", "ようやく": "finally, at last", "気づく": "to notice, to realize", "備え": "preparation", "教え": "teaching, lesson"}, "gramEn": {"引用の「と」": {"exp": "「と」 marks what someone said or thought, and is followed by verbs like 言う, 答える, 思う, or 笑う. Direct quotation keeps the original words verbatim (「〜」と); indirect quotation uses a plain-form clause + と (明日来ると言った = \"said he would come tomorrow\").", "ex": ["He said, \"Thank you.\"", "I think it will be sunny tomorrow. (indirect quotation)"]}, "〜てばかりいる": {"exp": "\"To do nothing but…,\" usually with a tone of reproach. 「遊んでばかりいる」 = \"does nothing but play.\" After a noun, attach 「〜ばかり」 directly: 歌ばかり歌う (does nothing but sing).", "ex": ["Stop doing nothing but staring at your phone, and go study."]}, "〜なさい": {"exp": "Verb ます-stem + なさい is a command or piece of advice in the tone of an elder or teacher. It's gentler than the plain imperative but stronger than 「〜てください」. It's common in fables and parental speech: 「考えなさい」 (think about it).", "ex": ["Go to bed soon."]}, "〜のに / 〜てしまう": {"exp": "「〜のに」 = \"even though / although,\" with a sense of surprise or dissatisfaction: 「食べ物があるのに働く」 (works even though there's plenty of food). 「〜てしまう」 marks completion or regret: 「枯れてしまった」 (it all withered — said with regret).", "ex": ["Even though we'd made plans, he didn't come.", "I ended up forgetting my wallet."]}}, "convEn": ["A: That person does nothing but play, huh. B: They really ought to think about the future, too.", "A: You still haven't finished your homework? B: Yeah… I got told to hurry up and do it.", "A: I forgot my umbrella and got soaked. B: Oh dear, that must have been rough."], "extEn": ["Quotative 「と」: direct quotation copies the words exactly (「〜」と); indirect quotation turns them into plain form + と. The same と is used before 思う, 書く, and 聞く.", "「〜てばかり」 (nothing but, with reproach) vs. 「〜だけ」 (a neutral \"only\"). Narratives often use てばかり to describe a bad habit.", "The proverb 「備えあれば憂いなし」 = \"preparedness prevents misfortune\" — it maps almost exactly onto the Chinese. Reading fables is a great way to pick up such maxim-style expressions."], "reflectEn": ["Use the quotative 「と」 to relay something someone once said to you.", "Make a sentence with 「〜てばかりいる」 describing someone's bad habit.", "Write the proverb 「備えあれば憂いなし」 from memory, and state its meaning."]}, "14": {"themeEn": "Week 2 Wrap-up — Over This Past Week", "goalsEn": ["Reuse N3 grammar within a single short essay", "Self-test by reading aloud with the kana covered", "Write your own short N3 reflection essay"], "paraEn": ["Over this past week, I have learned many new expressions.", "On my teacher's advice, I made a point of practicing out loud every day, so I feel I can now speak more naturally than before.", "According to the weather forecast, it's going to get cold next week, but cold or not, I plan to keep studying.", "If you want to get good at Japanese, you mustn't be afraid of making mistakes — that's what one teacher told me.", "Each time my mistakes get corrected, I feel myself growing little by little.", "If I can keep this up for a month, I'm sure even I will notice the change in myself.", "Sometimes it gets so hard that I start to hate it, but those are exactly the times, I think, when I should go back to the basics.", "Without rushing, yet without resting either, I want to keep moving forward one step at a time from here on."], "vocabEn": {"一週間": "one week", "表現": "expression", "恐れる": "to fear, to be afraid of", "〜たびに": "every time, each time", "基本": "the basics", "戻る": "to return, to go back", "時々": "sometimes"}, "gramEn": {"① 原因・理由 复习": {"exp": "Review — cause/reason: ので (soft, polite), から (subjective), ため (cause/purpose), おかげで (thanks to), せいで (blaming). From the passage: 「勧められたので」 (because I was advised to).", "ex": ["Because it's raining, the match is canceled."]}, "② 受身・使役 复习": {"exp": "Review — passive/causative: passive (勧められる, 直される), causative (させる), causative-passive (させられる). From the passage: 「先生に勧められて」 (advised by my teacher) and 「直されるたびに」 (each time I'm corrected).", "ex": ["I was made to give a presentation, and I got nervous."]}, "③ 伝聞・推量 复习": {"exp": "Review — hearsay/conjecture: そうだ (hearsay/appearance), らしい, ようだ, みたい. From the passage: 「寒くなるそうだ」 (I hear it'll get cold).", "ex": ["It seems he isn't coming."]}, "④ 条件 复习 ＋ 〜たびに": {"exp": "Review — conditionals: なら, ば, たら, と. From the passage: 「上手になりたいなら」 (if you want to get good) and 「続けられれば」 (if I can keep it up). 「〜たびに」 = \"every time… , …\"", "ex": ["Every time I hear this song, I'm reminded of my hometown."]}, "⑤ 敬語 复习": {"exp": "Review — keigo: おっしゃる (to say, respectful) and 〜べきだ (should/ought to). From the passage: 「先生がおっしゃっていました」 (the teacher was saying) and 「基本に戻るべきだ」 (should go back to basics).", "ex": ["The teacher said so."]}}, "convEn": ["A: You've gotten a lot better at speaking lately. B: It's thanks to making a point of practicing every day.", "A: Doesn't it get so hard that you start to hate it? B: It does. But I figure those are exactly the times I should keep going.", "A: I hear it's going to get cold next week. B: Cold or not, I'm not taking a break from studying."], "extEn": ["This week's checklist: 〜ので/から/ため/おかげで/せいで・passive/causative/causative-passive/adversative-passive・と/たら/ば/なら・〜そうだ (hearsay/appearance)/らしい/ようだ/みたい・respectful & humble language・quotative と・〜てばかり・〜なさい・〜のに・〜てしまう・〜たびに.", "Reading traps: 楽[らく]/楽[たの]しい, 通[つう]じる/通[とお]す, 間[ま]に合う/間[あいだ], 方[かた]/方[ほう], 母[はは] — same characters, multiple readings; these are exactly what to keep an eye on.", "Study method: cover the kana and read today's passage aloud once. Any word you stumble on is one to focus on with listen-and-repeat practice next week."], "reflectEn": ["[Big weekly assignment] Using this week's N3 grammar, write a 6–8 sentence reflection essay titled 「この一週間で」 (\"Over this past week\").", "Cover the kana and read the whole passage aloud, circling the words you can't read accurately, and compile them into your personal \"reading error notebook.\"", "Make one sentence each with 「〜たびに」 and 「〜べきだ」 about studying."]}, "15": {"themeEn": "Jobs ① — Connecting the Dots", "goalsEn": ["「〜という＋noun」: adding content to a noun", "「たとえ〜ても」: even if…", "「〜しかない」 (no choice but) and 「〜かもしれない」 (might)"], "paraEn": ["At Stanford University's commencement, Steve Jobs told three stories about his own life.", "The first was the story called \"connecting the dots.\"", "He had dropped out of college, but afterward he sat in on a class about the beauty of letterforms, a subject that had caught his interest.", "At the time, he had no idea at all what use it would ever be in the future.", "Yet ten years later, that knowledge came alive when he built the world's first computer with beautiful typography.", "He put it this way: \"You can't connect the dots looking forward. Only looking back do the dots connect.\"", "In other words, you can only trust that what you're doing now will, someday, surely connect to something.", "Even if it seems pointless now, that experience may well be shaping your future self.", "So I, too, want to believe in today's small efforts and keep at them."], "vocabEn": {"卒業式": "graduation ceremony", "人生": "life", "中退する": "to drop out (of school)", "文字": "letters, typography", "役に立つ": "to be useful, to come in handy", "知識": "knowledge", "生きる": "to be put to good use", "先": "ahead, the future", "振り返る": "to look back", "つながる": "to be connected (intransitive; cf. つなぐ, transitive)", "無駄": "waste, pointless", "未来": "the future", "努力": "effort"}, "gramEn": {"〜という＋名词": {"exp": "Adds \"content\" or a name to the noun that follows. 「点をつなぐという話」 = \"the story (called) 'connecting the dots'\"; 「働きたいという気持ち」 = \"the feeling of wanting to work.\" It packages a whole clause into a modifier for the noun.", "ex": ["I have a goal: to make my dream come true."]}, "たとえ〜ても": {"exp": "「たとえ」 works together with 「〜ても」 to stress \"even in the most extreme case, still…\" 「たとえ無駄に思えても、続ける」 = \"even if it seems pointless, I'll keep going.\"", "ex": ["Even if I fail, I won't have any regrets."]}, "〜しかない": {"exp": "Verb dictionary form + しかない = \"have no choice but to…, there's nothing for it but to…\" 「信じるしかない」 (have no choice but to believe). It's close to 「〜ほかない」 (slightly more written).", "ex": ["Having come this far, there's nothing to do but go for it."]}, "〜かもしれない": {"exp": "Attaches to the plain form to express an uncertain guess — \"might, perhaps.\" It's less confident than 「だろう」. 「作るのかもしれない」 (might be making it).", "ex": ["He might already know."]}}, "convEn": ["A: What's even the point of studying this? B: You may not see it now, but it might connect to something someday.", "A: I want to give up already. B: Having come this far, you've got no choice but to keep going.", "A: How was studying abroad? B: Looking back on it, it was a truly great experience."], "extEn": ["「〜という＋noun」 is a powerful way to \"stuff\" an entire sentence into a noun, and it's high-frequency in speeches, argumentative writing, and conversation alike: 「諦めないという気持ち」 (the resolve not to give up).", "「しかない」 (no choice but, resigned) ≈ 「〜ほかない」; distinguish it from 「〜だけだ」 (merely / only, neutral).", "Today's famous line: 「先を見て点はつなげない。振り返って初めてつながる。」 — memorize it as a personal mantra."], "reflectEn": ["Use 「たとえ〜ても」 to write a sentence about persevering in your studies.", "Use 「〜しかない」 to describe some situation you're in right now.", "Recite and write from memory Jobs's \"connecting the dots\" quote (in Japanese)."]}, "16": {"themeEn": "Jobs (Stanford Speech) #2 — Love and Loss", "goalsEn": ["\"〜てしまう\" for regret / completion", "\"〜ように感じる\" to feel as if…", "\"〜なければ\" negative condition + special number readings"], "paraEn": ["The second story is about \"love and loss.\"", "When Jobs was twenty, he started Apple in a small garage with a friend.", "The company grew large, but at thirty he ended up being driven out of the very company he had built.", "In the middle of his life, he says, he felt as if he had lost everything.", "Later, though, he put it this way: \"Getting fired from Apple was the best thing that ever happened to me.\"", "It was because he had been freed from the weight of \"success\" and could once again take on challenges freely.", "He says: \"The only way to do great work is to love what you do.\"", "Even when things are painful, as long as you don't give up what you love, the road will open again.", "—It's an unforgettable story that teaches us exactly that."], "vocabEn": {"喪失": "loss", "二十歳": "twenty years old (special reading)", "成長する": "to grow, to develop", "追い出す": "to drive out, to force out", "真ん中": "the middle, the center", "失う": "to lose", "語る": "to tell, to narrate", "出来事": "event, happening", "解放する": "to release, to set free (〜から解放される = to be freed from…)", "挑戦する": "to take on a challenge", "唯一": "the only, sole", "諦める": "to give up", "道が開ける": "a path opens up, things take a turn for the better"}, "gramEn": {"〜てしまう / 〜ちゃう": {"exp": "Attaches to the te-form to show that an action is completely finished, or—very often—that it happened to one's regret or dismay: 「追い出されてしまった」(ended up being driven out). In casual speech 〜てしまう contracts to 〜ちゃう, and 〜でしまう to 〜じゃう.", "ex": ["I went and forgot an important promise.", "I ate the whole thing! (casual)"]}, "〜ように感じる / 〜ようだ": {"exp": "「〜ように感じる／思う」means to feel as if… or to feel as though…: 「すべてを失ったように感じた」. It is also used for comparisons, as in 「夢のようだ」(it's like a dream).", "ex": ["I felt as if time had stopped."]}, "〜なければ、〜": {"exp": "A negative condition: drop the い from a verb's ない-form and add ければ. 「諦めなければ、道は開ける」= as long as you don't give up, the road will open. It's roughly equivalent to 「諦めなかったら」.", "ex": ["If you don't hurry, you won't make it in time."]}, "〜という＋抽象名词": {"exp": "A review and step up: making an abstract idea concrete. 「成功という重さ」= the weight that is \"success\"; 「自由という名の責任」= the responsibility that goes by the name of \"freedom.\" It's quite rhetorical and common in speeches.", "ex": ["To think about the meaning of the word \"freedom.\""]}}, "convEn": ["A: Quitting your job—aren't you anxious about it? B: I am anxious, but I don't want to give up what I love.", "A: I failed, and I'm feeling down. B: It's hard now, but someday it'll become a valuable experience.", "A: Why did you choose this job? B: Because I want to love what I do."], "extEn": ["Special readings to memorize: 二十歳[はたち]・二十日[はつか]・一人[ひとり]・二人[ふたり]・一日[ついたち](the 1st). These kun readings are tested at N2 too.", "「クビになる」(to get canned, casual) vs.「解雇される」(to be dismissed, formal): same meaning, different register—using the casual word in a speech feels warmer.", "Today's famous line: \"The only way to do great work is to love what you do.\""], "reflectEn": ["Use \"〜なければ、〜\" to write one sentence encouraging yourself.", "Write out from memory the line \"素晴らしい仕事をする唯一の方法は、自分のすることを愛することだ.\"", "Review the special readings 二十歳・二十日・一人・二人—read each three times and write out the kana."]}, "17": {"themeEn": "Jobs (Stanford Speech) #3 — On Death / Stay Hungry", "goalsEn": ["\"〜てはいけない\" for prohibition", "\"〜であれ\" literary imperative (maxim style)", "\"〜以来\" since… · \"〜（よ）うとする\""], "paraEn": ["The third story is about \"death.\"", "When Jobs was seventeen, he came across a certain saying.", "\"If you live each day as if it were the last day of your life, someday you'll surely be right.\"", "Ever since, he says, he would look in the mirror each morning and ask himself a question.", "\"If today were the last day, would I really want to do what I'm about to do now?\"", "Thinking about death, he says, frees us from the fear of losing something.", "\"Your time is limited, so don't waste it living someone else's life.\"", "And in the end, he closed his speech with these words: \"Stay hungry. Stay foolish.\"", "—It means: keep learning always, and move forward without fear."], "vocabEn": {"死": "death", "最後": "the last (↔ 最初 the first)", "その通り": "exactly so, just like that", "〜以来": "since…", "鏡": "mirror", "問いかける": "to ask (oneself), to put a question to", "恐怖": "fear, terror", "限られる": "to be limited", "他人": "others, other people", "終える": "to finish (transitive; ↔ 終わる intransitive)", "愚か": "foolish", "常に": "always, constantly", "恐れる": "to fear, to be afraid of"}, "gramEn": {"〜てはいけない / 〜ちゃいけない": {"exp": "Prohibition: verb te-form + はいけない. 「無駄にしてはいけない」= you must not waste it. The casual contraction is 〜ちゃいけない. Learn it as a set with obligation 「〜なければならない」 and permission 「〜てもいい」.", "ex": ["You may not take photos here."]}, "〜であれ": {"exp": "A strong imperative / maxim form derived from 「である」, common in speeches and slogans. 「ハングリーであれ」= (you should) stay hungry. In everyday speech you'd say 「〜でいて」 instead.", "ex": ["Always be honest."]}, "〜以来": {"exp": "「noun / verb te-form + 以来」means ever since…(and continuously thereafter). 「それ以来」(ever since then), 「卒業して以来」(ever since graduating).", "ex": ["I haven't been back even once since coming to Japan."]}, "〜（よ）うとする": {"exp": "Volitional form + とする = to be about to do… or to try to do… 「やろうとしていること」= what one is about to do. 「出かけようとしたとき、電話が鳴った」(just as I was about to go out, the phone rang).", "ex": ["I tried to stand up, but my leg hurt too much to move."]}}, "convEn": ["A: If today were your last day, what would you do? B: I'd say \"thank you\" to the people who matter to me.", "A: I worry too much about what others think… B: There's no need to live someone else's life.", "A: I'm afraid of failing. B: Don't be afraid—just give it a try."], "extEn": ["The rules set of three: 〜てはいけない (prohibition) / 〜なければならない (obligation) / 〜てもいい (permission).", "The literary imperative 「〜であれ」: used in speeches, slogans, and fables—strong and formal (正直であれ・自由であれ). In daily life, use 「〜でいてね」.", "Today's famous lines: \"Your time is limited\" + \"Stay hungry, stay foolish.\""], "reflectEn": ["Use \"〜てはいけない\" to write one reminder to yourself.", "Write out the whole line \"あなたの時間は限られている…\" from memory.", "Copy out \"ハングリーであれ。愚か者であれ。\" and read it aloud three times."]}, "18": {"themeEn": "Stating an Opinion — Scores, or the Joy of Getting Through", "goalsEn": ["\"〜について\" (about) vs. \"〜に対して\" (toward / attitude)", "Tentative claims with \"〜のではないか\"", "\"〜と言える\" (it can be said)"], "paraEn": ["When it comes to learning a language, I have one opinion.", "Many people take a strong interest in their test scores.", "Of course, scores are an expression of the results of one's effort, and are by no means meaningless.", "But isn't the true purpose of language to share feelings with others?", "According to one survey, many of the people who can speak a foreign language are those who aren't afraid of making mistakes.", "From this, you might say that what's needed to improve isn't talent, but courage.", "More than perfect grammar, it's the desire to get something across that matters.", "That's exactly why I believe we should value not only scores, but also \"the joy of getting through to someone.\""], "vocabEn": {"言語": "language (written/formal)", "意見": "opinion, view", "点数": "score, marks", "関心": "interest, concern (≠ 感心 to be impressed)", "表す": "to express, to represent", "決して〜ない": "never, by no means", "目的": "purpose, aim", "通じ合う": "to understand each other, to connect", "調査": "survey, investigation", "才能": "talent", "勇気": "courage", "完璧": "perfect", "伝わる": "to be conveyed, to get through (intransitive; ↔ 伝える to convey)"}, "gramEn": {"〜について": {"exp": "Neutrally introduces a topic: \"about…\" or \"concerning…\". 「学ぶことについて意見がある」(I have an opinion about learning). It's followed by verbs like 話す, 考える, 調べる, 書く, etc.", "ex": ["I'll give a presentation about environmental problems."]}, "〜に対して": {"exp": "Marks the target of an attitude or action toward someone/something, or expresses a contrast. 「点数に対して関心を持つ」(to take an interest in scores); 「年上の人に対して敬語を使う」(to use polite language toward elders). For contrast: 「兄は静かなのに対して、弟は活発だ」(the older brother is quiet, whereas the younger one is lively).", "ex": ["You must not take a rude attitude toward customers."]}, "〜のではないか / 〜ではないでしょうか": {"exp": "A softer, more tactful way to put forward a claim than a flat assertion—a \"golden\" pattern for N2 writing. 「目的は通じ合うことではないでしょうか」(isn't the purpose to connect with one another?).", "ex": ["Shouldn't we talk it over more?"]}, "〜と言える / 〜ではなく〜": {"exp": "「〜と言える」= it can be said that…(drawing a conclusion); 「AではなくB」= not A but B (a common contrast in argumentative writing). 「才能ではなく、勇気だと言える」(you could say it's not talent but courage).", "ex": ["You could say this isn't a coincidence, but the result of hard work."]}}, "convEn": ["A: What do you think about this issue? B: I think it may be a little different, actually.", "A: Is there anything you'd like to say about his opinion? B: I agree, but there's just one point I'm concerned about.", "A: If you work hard, can you succeed? B: I can't say it's guaranteed, but the odds do go up."], "extEn": ["「について」(neutral · about) vs.「に対して」(directed at a target/attitude · or contrast): 環境について話す (talk about the environment) ↔ 環境に対して責任を持つ (take responsibility toward the environment).", "Three tentative-claim phrases: 「〜のではないか」「〜と言えるのではないか」「〜べきだと思う」—more tactful than flat assertions, and they earn points in exam essays.", "The argument skeleton: ① claim (I think…) ② concession (of course, it's true that…) ③ pivot (however…) ④ evidence (according to…) ⑤ conclusion (that's exactly why we should…). This passage follows just that structure."], "reflectEn": ["Write one sentence each with \"について\" and \"に対して\" to feel the difference between \"about\" and \"toward.\"", "Use \"〜のではないでしょうか\" to state one of your own views tactfully.", "Write the final sentence about \"伝わる喜び\" from memory, and memorize the five-step argument skeleton."]}, "19": {"themeEn": "Society and Technology — The Price of Convenience", "goalsEn": ["Word-building with \"〜化する\" and \"〜的\"", "\"〜つつある\" gradual change (written) · \"〜に伴って\" along with", "\"〜ば〜ほど\" the more… the more…"], "paraEn": ["In recent years, our lives have been changing rapidly.", "Thanks to the spread of smartphones, we've become able to obtain information anytime, anywhere.", "Society as a whole has rapidly gone digital, and the convenience is incomparable to before.", "On the other hand, as technology advances, new problems are also being born.", "For instance, some point out that opportunities to talk to people directly are decreasing, and that human relationships are growing thin.", "There are also voices worrying that the more convenient things become, the weaker our ability to think for ourselves may grow.", "Technology in itself is neither good nor bad.", "What matters is how we, the ones who use it, choose to face it.", "An attitude of not being swept along by convenience, but judging with one's own mind, will surely be demanded more and more from here on."], "vocabEn": {"近年": "recent years", "急速に": "rapidly", "普及": "spread, diffusion", "得る": "to obtain, to gain (written)", "全体": "the whole, the entirety", "比べものにならない": "incomparable, no comparison", "発展": "development, advancement", "直接": "directly (↔ 間接 indirectly)", "希薄": "thin, weak, sparse", "指摘": "to point out, an observation", "〜に流される": "to be swept along by…, to be carried away by…", "判断": "judgment", "姿勢": "attitude, stance", "求める": "to seek, to demand"}, "gramEn": {"〜化する / 名词＋化": {"exp": "Noun + 化 = -ization (becoming a … state). デジタル化 (digitization), 国際化 (internationalization), 高齢化 (aging), 自動化 (automation). Extremely productive and very frequent in N2 reading. 「社会がデジタル化する」.", "ex": ["This town, too, is seeing growing decline in the birthrate and aging of the population."]}, "〜つつある": {"exp": "Verb stem (ます-form) + つつある = to be gradually …(written, formal); it sounds more literary than 「〜ている」. 「変化しつつある」(is gradually changing).", "ex": ["The Earth's environment is steadily worsening."]}, "〜に伴って": {"exp": "「noun / verb + に伴って」= along with…(two things changing in step), written style. 「発展に伴って問題も生まれる」(along with development, problems arise too). Roughly equivalent to 「〜とともに」.", "ex": ["As the population increases, housing is running short."]}, "〜ば〜ほど": {"exp": "The ば-form of a verb/adjective + its plain form + ほど = the more…, the more…. 「便利になればなるほど」(the more convenient it becomes), 「考えれば考えるほど」(the more you think about it).", "ex": ["The more you practice, the more confidence you gain."]}}, "convEn": ["A: I hear fewer people are reading books these days. B: Yes, it's probably down to the spread of smartphones.", "A: Is the advance of technology nothing but good? B: No—along with it, problems are increasing too.", "A: I'm anxious my job might get taken by AI. B: If you move to the side that uses it, there's no need to worry."], "extEn": ["「〜化（か）」as a string to memorize: 国際化・少子化・高齢化・自動化・温暖化・民主化. When you see it, you know it means \"becoming….\"", "「〜的（てき）」turns a noun into a na-adjective: 社会的・経済的・具体的・積極的・一般的. Just as productive.", "Adverbs describing trends: 急速に・徐々に・ますます・次第に・確実に—the adverbs used to describe change in argumentative writing."], "reflectEn": ["Write one sentence each with \"〜化する\" and \"〜に伴って\" about a change in society.", "Use \"〜ば〜ほど\" to write a sentence about technology being a double-edged sword.", "Write the final sentence (about the stance of \"judging with one's own mind\") from memory."]}, "20": {"themeEn": "Contrast and Concession — Those Who Keep Going, Those Who Don't", "goalsEn": ["\"〜反面\" and \"〜一方で\" for listing two sides", "\"〜にもかかわらず\" despite (written)", "\"〜がち\" tends to / is prone to (mostly negative)"], "paraEn": ["When you're trying to master something, each person has a method that suits them.", "Studying alone lets you go at your own pace, but on the flip side you tend to slack off without realizing it.", "Conversely, learning together with others offers plenty of stimulation, but on the other side of that, you have to adapt to other people.", "A friend of mine, despite being extremely busy, studies Japanese every single day without fail.", "I, on the other hand, sometimes can't bring myself to sit down at the desk even though I have the time.", "Recently I've realized that it isn't a matter of time—in the end, it's a matter of mindset.", "Even though there are so many convenient tools, the reason I can't keep at it is, after all, probably because my will is weak.", "That's exactly why finding a method that suits me and keeping it up without forcing it is what matters most of all."], "vocabEn": {"身につける": "to acquire, to master (a skill)", "それぞれ": "each, respectively", "やり方": "way of doing, method", "怠ける": "to be lazy, to slack off", "反対に": "on the contrary, conversely", "刺激": "stimulation", "合わせる": "to adjust to, to accommodate", "欠かさず": "without fail, never missing", "結局": "after all, in the end", "道具": "tool", "意志": "will, willpower (≠ 意思 intention/meaning)", "無理なく": "without overdoing it, comfortably"}, "gramEn": {"〜一方（で）": {"exp": "Lists two sides of the same thing, or two things happening in parallel. 「進められる一方で、怠けがちだ」(you can make progress, but on the other hand you tend to slack off). It can also start a sentence on its own—「一方（で）、…」—to mean \"on the other hand.\"", "ex": ["While my income went up, my free time went down."]}, "〜反面": {"exp": "「〜反面」= the other side of…(the positive and negative sides of one and the same thing). 「刺激が多い反面、疲れる」(it's stimulating, but on the flip side it's tiring). It connects like the plain form (for nouns, 名詞＋である反面).", "ex": ["This job pays well, but on the other side of that, the responsibility is heavy too."]}, "〜にもかかわらず": {"exp": "Despite…/ even though…—more written and more emphatic about the \"unexpectedness\" than 「〜のに」. It attaches to the plain form or a noun. 「忙しいにもかかわらず、続けている」(keeps going despite being busy).", "ex": ["Despite all my effort, no results came of it."]}, "〜がち / 〜のに": {"exp": "「〜がち」= to tend to / be prone to…(usually negative): 怠けがち (prone to slacking), 忘れがち (apt to forget), 遅れがち (tends to run late). 「〜のに」= even though…(colloquial, with a note of complaint): 「時間があるのに、できない」(I can't do it even though I have the time).", "ex": ["In winter I tend to shut myself up at home."]}}, "convEn": ["A: Isn't this job tough? B: It's tough, but on the flip side it's also rewarding.", "A: He studies so much even though he's busy. B: Keeping it up every day despite being busy—amazing.", "A: Lately I keep eating too much. B: On days off you do tend to laze around, don't you."], "extEn": ["Strength of contrast: のに (colloquial · with a note of complaint) < にもかかわらず (written · emphasizes surprise); 反面 / 一方で (listing two sides · neutral, argumentative).", "「〜がち」(tends to / is prone to · mostly negative) vs.「〜っぽい」(seems like / has a tendency toward): 忘れがち (apt to forget) ↔ 忘れっぽい (forgetful by nature).", "Easily confused words: 意志 (will, resolve) ≠ 意思 (intention, meaning)—same sound, different characters; watch the context."], "reflectEn": ["Write one sentence each with \"〜反面\" and \"〜一方で\" describing two sides of something.", "Use \"〜にもかかわらず\" to write a sentence about someone's effort.", "Write from memory the sentence about \"in the end, it's a matter of mindset.\""]}, "21": {"themeEn": "Week 3 Wrap-Up — What I Learned from the Speeches", "goalsEn": ["「〜にちがいない」surely/must be · 「〜わけではない」it's not that…", "「〜に対する」toward… (noun modifier)", "Reinforcing speeches through reading aloud and shadowing"], "paraEn": ["Over this past week, I learned a great deal through Steve Jobs's speeches.", "Of everything he said, what moved me most was the idea that \"you can only connect the dots looking backward.\"", "I've come to believe that the steady, unglamorous practice I'm doing now must surely lead somewhere one day.", "It's not that my anxiety about exam scores has gone away.", "But I've started to feel that, rather than chasing scores alone, I also want to cherish the \"joy of getting through to someone.\"", "A speech is structured like a piece of writing, yet at the same time it carries the warmth of spoken words.", "That's exactly why, when you read one aloud, you can learn not just grammar but also how to pour your feelings into it.", "For the days that remain, I want to stay hungry and keep moving forward without fear."], "vocabEn": {"心を動かす": "to move (someone's heart), to touch", "地道": "steady, down-to-earth", "追いかける": "to chase, to pursue", "構成する": "to compose, to structure", "温かさ": "warmth", "込める": "to put (feeling) into", "残り": "the rest, what remains", "日々": "(one's) days, daily life"}, "gramEn": {"〜にちがいない": {"exp": "Expresses a confident inference based on evidence: \"surely…\" or \"…must be the case.\" Far more certain than かもしれない, and more subjectively convinced than はずだ. As in 「つながるにちがいない」(it must surely connect).", "ex": ["Judging by how he acted, he must have known too."]}, "〜わけではない": {"exp": "A partial denial: \"it's not (entirely) that…\" 「不安がなくなったわけではない」means \"it's not that the anxiety has vanished.\" Often follows a \"that said…\" turn of thought.", "ex": ["It's not that I dislike it, I just don't eat much of it."]}, "〜に対する＋名词": {"exp": "When 「〜に対して」modifies a noun, it becomes 「〜に対する＋noun」. 「点数に対する不安」means \"anxiety about (one's) scores.\"", "ex": ["Interest in the environment is on the rise."]}, "〜のではなく / 〜だけでなく": {"exp": "A review of contrast in argumentative writing: 「点数だけを追いかけるのではなく」(not just chasing scores) and 「文法だけでなく…も」(not only grammar, but also…). Both are powerful connectors for N2 essays.", "ex": ["Not just quantity, but quality matters too."]}}, "convEn": ["A: Which story stayed with you the most? B: The \"dots\" one. It made me feel that the effort I'm putting in now isn't wasted.", "A: Feeling confident now? B: It's not that I'm confident exactly, but I'm less scared than before.", "A: Do you think he'll pass? B: After all that effort, he surely will."], "extEn": ["Reviewing three famous lines: ① \"You can only connect the dots looking backward.\" ② \"Love what you do.\" ③ \"Stay hungry. Stay foolish.\"", "Shadowing: play the audio slowly and read along half a beat behind, imitating the intonation and pauses—this is the key drill for turning \"written structure\" into \"speaking ability.\"", "Degrees of certainty in inference: かもしれない ＜ だろう ＜ にちがいない ≈ はずだ. Choose based on how sure you are when writing."], "reflectEn": ["Pick the line that moved you most from the three speeches, then copy it out and memorize it.", "Write one sentence each using 「〜にちがいない」and 「〜わけではない」.", "Practice today's passage three times with shadowing, then record yourself and compare your intonation."]}, "22": {"themeEn": "Haruki Murakami — Of Walls and Eggs", "goalsEn": ["「AとはBのことだ」giving a definition", "「どんなに〜ても」no matter how…", "「〜やすい/〜にくい」and figurative expression"], "paraEn": ["The writer Haruki Murakami gave an unforgettable speech at an awards ceremony.", "He said this: \"If there is a high, solid wall and an egg that breaks against it, I will always stand on the side of the egg.\"", "The \"wall\" he speaks of here refers to the vast forces and systems that try to crush each one of us.", "And the \"egg\" refers to the individual human being—fragile, breakable, and irreplaceable.", "No matter how right the wall may appear, nothing is more precious than the human heart and human life: that is what he wanted to convey.", "The reason this speech resonated with so many people is, I think, that it used no difficult words.", "By using a simple metaphor, he spoke of a profound idea in a way anyone could understand.", "I, too, hope that someday I can speak about what truly matters in my own words."], "vocabEn": {"作家": "writer, author", "授賞式": "award ceremony", "固い": "hard, solid", "ぶつかる": "to collide, to crash into", "割れる": "to break, to shatter (intransitive)", "常に": "always, at all times", "側": "side", "押しつぶす": "to crush, to flatten", "仕組み": "system, structure, mechanism", "かけがえのない": "irreplaceable", "命": "life", "響く": "to resonate, to strike a chord", "比喩": "metaphor"}, "gramEn": {"AとはBのことだ": {"exp": "Used to define or explain a term or concept. 「ここで言う『壁』とは、…のことです」means \"the 'wall' referred to here is….\" Essential for argumentative writing and speeches.", "ex": ["A freelancer is someone who works without belonging to a company."]}, "どんなに〜ても": {"exp": "「どんなに ＋ adjective/verb ＋ ても」means \"no matter how…\" As in 「どんなに正しく見えても」(no matter how right it looks). Roughly equivalent to 「いくら〜ても」.", "ex": ["No matter how tired I am, the one thing I always do is write in my diary."]}, "〜やすい / 〜にくい": {"exp": "Verb stem (ます-form) ＋ やすい/にくい means \"easy/hard to do.\" Examples: 「壊れやすい」(fragile), 「割れやすい」, 「読みにくい」(hard to read), 「分かりやすい」(easy to understand).", "ex": ["This pen is easy to write with."]}, "〜（よ）うとする ＋ 名词": {"exp": "A review, used as a modifier: volitional form ＋ とする ＋ noun means \"a (something) that is trying/about to…\" 「押しつぶそうとする力」means \"the force that tries to crush (you).\"", "ex": ["The will to keep moving forward is what matters."]}}, "convEn": ["A: This speech has no difficult words, does it? B: That's exactly why it can reach everyone's heart.", "A: What does \"the wall\" mean? B: It refers to the vast force that holds people down.", "A: Using a metaphor makes it easy to grasp. B: Yes, the harder the topic, the more simply you should explain it."], "extEn": ["「AとはBのことだ／AというのはBということだ」is the standard pattern for explaining a term—indispensable for argumentative essays and speeches alike.", "「〜やすい／〜にくい」attaches to the ます-stem: 燃えやすい (flammable), 割れやすい (breakable), 覚えにくい (hard to memorize), 言いにくい (hard to say).", "The power of a central metaphor: rendering the abstract (power, systems) as something concrete (a wall), and the individual as an egg—one good metaphor can carry an entire speech."], "reflectEn": ["Use 「AとはBのことだ」to define a word (such as 「自由」or 「勇気」).", "Write one sentence each using 「〜やすい」and 「〜にくい」.", "Write out from memory the full line: 「高くて固い壁と…私は常に卵の側に立つ」."]}, "23": {"themeEn": "Written Language and Spoken Language — Two Faces", "goalsEn": ["The 「である」style and contracted forms", "Switching registers by situation and audience (使い分ける)", "Recognizing connectors specific to writing vs. speech"], "paraEn": ["Japanese has two faces: written language and spoken language.", "Even with the same content, you have to change how you say it depending on the situation.", "For example, to a friend you say 「行かなきゃ」(gotta go), but in writing you write 「行かなければならない」(must go).", "In academic papers and the news, the stiff 「〜である」style is commonly used.", "On the other hand, in conversation, softer expressions like 「〜なんだ」and 「〜けど」feel natural.", "In spoken language, 「〜してしまう」can shrink to 「〜しちゃう」, and 「〜ておく」to 「〜とく」.", "If you don't know these differences, you may end up making a rude impression in a formal setting.", "Conversely, if you use overly stiff language with a close friend, you come across as distant.", "In other words, what matters is the ability to use language flexibly, adapting it to your listener and the situation."], "vocabEn": {"内容": "content", "場面": "scene, situation", "言い方": "way of saying, phrasing", "論文": "academic paper", "硬い": "stiff, formal", "文体": "writing style, register", "縮む": "to shrink, to contract", "フォーマル": "formal", "失礼": "rude, impolite", "印象を与える": "to give an impression", "よそよそしい": "distant, aloof", "使い分ける": "to use selectively (per situation)"}, "gramEn": {"「である」体 vs「です・ます」体": {"exp": "The 「である」style is used for papers, news, and explanatory writing (だ→である; noun ＋ である); the 「です・ます」style is for ordinary polite contexts. A single text must stick to one—never mix them.", "ex": ["This is an important problem. (これは重要な問題である。 written style / これは重要な問題です。 polite style)"]}, "縮約形（话し言葉）": {"exp": "Common spoken contractions: 〜てしまう→ちゃう, 〜ておく→とく, 〜なければ→なきゃ, 〜ている→てる, 〜ては→ちゃ, 〜という→って. Essential for listening and conversation.", "ex": ["I'd better get the homework done. (a contraction of やっておかなければ)"]}, "話し言葉のつなぎ": {"exp": "Casual connectors: けど (but), だって (because/but), じゃ (= では), でも (but). More casual and friendly than written ones. 「行きたいけど、時間がなくて」(I want to go, but I don't have time…).", "ex": ["I want to go, but I don't have any money."]}, "書き言葉のつなぎ": {"exp": "Formal written connectors: および (and), または (or), なお (also/note that), ただし (however), したがって (therefore). Indispensable for reading argumentative texts; almost never used in speech.", "ex": ["An application form and a form of ID are required."]}}, "convEn": ["A: Can I write 「〜だと思う」(I think that…) in my report? B: The stiffer 「〜と考えられる」(it can be considered that…) is better.", "A: What's 「やっとく」? B: It's the spoken form of 「やっておく」.", "A: Is 「〜っす」not okay in an interview? B: No, no—make sure you say 「〜です」properly."], "extEn": ["Contraction chart: 〜てしまう→ちゃう / 〜でしまう→じゃう, 〜ておく→とく, 〜なければ→なきゃ・なくちゃ, 〜ている→てる, 〜ては→ちゃ, 〜という→って.", "For exam essays: pick either the です・ます style or the である style and keep it consistent throughout; spoken contractions must never appear in an essay.", "List of written connectors: および・または・ならびに・なお・ただし・したがって・すなわち—these appear frequently in the reading section."], "reflectEn": ["Rewrite the casual 「行かなきゃ、もう遅いし」in the written style.", "Write out the spoken contraction for each of 「〜てしまう・〜ておく・〜ている」.", "Write the final sentence (about the \"ability to use language flexibly\") from memory."]}, "24": {"themeEn": "N2 Grammar ① — をめぐって・にあたって・次第", "goalsEn": ["「〜をめぐって」concerning (a dispute)", "「〜にあたって」on the occasion of (a major event)", "The three uses of 「次第」"], "paraEn": ["Concerning the introduction of the new system, lively debate continues within the company.", "On the occasion of launching this project, it was decided to first hear everyone's opinions.", "Whether to support or oppose it depends on each person's standpoint.", "We plan to begin the work as soon as preparations are complete.", "On this topic, opinions are divided even among the experts.", "When making an important decision, careful investigation is indispensable.", "In the end, you could say that whether we succeed depends on our own effort.", "That is precisely why each individual needs to take responsibility and throw themselves into it."], "vocabEn": {"制度": "system, institution", "導入": "introduction, adoption", "社内": "within the company", "活発": "lively, active", "議論": "discussion, debate", "全員": "all members, everyone", "立場": "standpoint, position", "整う": "to be ready, to be in order", "作業": "work, task", "専門家": "expert, specialist", "意見が分かれる": "opinions are divided", "慎重": "careful, cautious", "取り組む": "to tackle, to work on"}, "gramEn": {"〜をめぐって / 〜をめぐる": {"exp": "Concerning a contested topic (sparking debate, conflict, or rivalry). 「導入をめぐって議論が続く」(debate continues over the introduction). To modify a noun, use 「〜をめぐる問題」.", "ex": ["The brothers are fighting over the inheritance."]}, "〜にあたって / 〜にあたり": {"exp": "\"On the occasion of\" doing something significant (beforehand, in a formal tone). 「計画を始めるにあたって」(on launching the project). Written and formal; in everyday speech use 「〜とき」.", "ex": ["On the occasion of starting my new life, allow me to say a few words."]}, "〜次第だ / 〜次第で": {"exp": "「noun ＋ 次第だ／で」means \"depends on…\" or \"varies according to….\" 「努力次第だ」(depends on effort), 「天気次第で中止」(cancelled depending on the weather).", "ex": ["Whether I go depends on tomorrow's weather."]}, "〜次第（、すぐに）": {"exp": "Verb stem (ます-form) ＋ 次第 means \"as soon as (immediately).\" A written way of saying \"at the earliest opportunity.\" 「整い次第、開始する」(begin as soon as ready). Note: same character, different meaning from the use above.", "ex": ["I'll contact you as soon as I arrive."]}}, "convEn": ["A: This matter seems contentious. B: Yes, there's a clash over the budget.", "A: When will you start? B: We'll start as soon as we get permission.", "A: Will it go well? B: That depends on how motivated you are."], "extEn": ["The three uses of 「次第」: ① noun ＋ 次第だ/で = depends on; ② verb ます-stem ＋ 次第 = as soon as (formal \"ASAP\"); ③ noun 「次第」= circumstances/the course of events (事の次第, こういう次第で).", "「をめぐって」pairs with disputes: 問題・事件・遺産・領土をめぐって ＋ 議論/対立/争う.", "「にあたって」is used beforehand for major occasions: 開会・入学・出発・契約にあたって. A more casual alternative is 「〜際（さい）に」."], "reflectEn": ["Write a sentence about some controversial topic using 「〜をめぐって」.", "Write one sentence each using the two senses of 「次第」(depends on / as soon as).", "Write 「成功するかどうかは…努力次第だ」from memory."]}, "25": {"themeEn": "N2 Grammar ② — It's Never Too Late", "goalsEn": ["「〜ざるを得ない」cannot help but / be forced to", "「〜どころか」far from / let alone", "「〜にすぎない」merely · 「〜さえ/こそ」"], "paraEn": ["In today's society, the pace of change is fast, and everyone is forced to keep learning.", "Some people say \"I'm not young anymore,\" but I think age is merely an excuse.", "In fact, there is no such thing as being \"too late\" to start something.", "Rather, there are even people who say they can learn more enjoyably once they've grown older.", "When you take on something new, at first—far from going well—you may do nothing but fail.", "But those very failures are the first step toward improvement.", "If you give up, deciding you can't do it, your chances drop to zero.", "So even when it feels hard, I have no choice but to take that first step—that's what I keep telling myself."], "vocabEn": {"スピード": "speed", "年齢": "age", "言い訳": "excuse", "実際": "actually, in fact", "むしろ": "rather, if anything", "年を取る": "to grow old, to age", "挑戦する": "to take on a challenge", "上達": "improvement, progress (in a skill)", "第一歩": "the first step", "可能性": "possibility, potential", "踏み出す": "to step forward, to take a step", "言い聞かせる": "to tell (oneself), to remind firmly"}, "gramEn": {"〜ざるを得ない": {"exp": "Verb ない-form minus ない ＋ ざるを得ない means \"cannot help but / be forced to\" (written, with a sense of reluctance). 「学び続けざるを得ない」. Note the irregular form: する → 「せざるを得ない」.", "ex": ["It's an order from my boss, so I have no choice but to obey."]}, "〜にすぎない": {"exp": "「noun／verb ＋ にすぎない」means \"is no more than / merely…\" (a low degree, nothing remarkable). 「言い訳にすぎない」(is merely an excuse).", "ex": ["I merely offered an opinion, that's all."]}, "〜どころか": {"exp": "The first clause is overturned, and the second is often the opposite or even more extreme: \"far from…, in fact…\" 「うまくいくどころか、失敗ばかり」(far from going well, nothing but failures).", "ex": ["Far from kanji, I couldn't even read hiragana."]}, "〜さえ / 〜こそ": {"exp": "「〜さえ」means \"even…\" (citing an extreme example): 「楽しく学べる人さえいる」(there are even people who can learn enjoyably). 「〜こそ」means \"precisely…\" (emphasis): 「失敗こそが第一歩」(failure is precisely the first step).", "ex": ["Even a child knows that.", "Now is precisely the time to start."]}}, "convEn": ["A: Working late again? B: The deadline's close, so I have no choice but to do it.", "A: Did he apologize? B: Far from apologizing, he actually got angry.", "A: What amazing talent. B: No, this is merely the result of practice."], "extEn": ["「ざるを得ない」(forced to; written, reluctant) ≈ 「〜しかない／〜なければならない」, but conveys more of a sense of compulsion. The irregular su-row form: せざるを得ない.", "「どころか」expresses \"dashed expectations + the reverse\": 役に立つどころか、邪魔になった (far from being useful, it got in the way).", "An emphasis ladder of focus particles: 〜さえ (even…), 〜すら (even…; more written), 〜こそ (precisely), 〜まで (even to the point of…)."], "reflectEn": ["Write a sentence about something you \"have no choice but to do\" using 「〜ざるを得ない」.", "Write a sentence where \"the result is the opposite of what was expected\" using 「〜どころか」.", "Write 「年齢は言い訳にすぎない」from memory."]}, "26": {"themeEn": "N2 Grammar ③ — The Night Before the Exam", "goalsEn": ["「〜たところで」 even if … (it won't help)", "「〜ないことには」 without … you can't", "「〜まい」 negative will / conjecture"], "paraEn": ["When the day before the exam arrives, no matter how much you panic, there's only so much you can do.", "Even if you pull an all-nighter now, you probably won't get much to stick in your head.", "More than that, unless you first calm down, you won't even be able to recall what you've memorized.", "If your foundation isn't solid, you simply can't solve the application problems.", "I've made up my mind that I will never panic when the real exam comes.", "No matter how hard the questions are, I'm determined never to give up.", "Worrying about the results won't make your score go up.", "So right now, all I can do is focus on the one question in front of me."], "vocabEn": {"前日": "the previous day", "いくら〜ても": "no matter how (much)", "限られる": "to be limited", "今さら": "now (when it's too late)", "徹夜する": "to stay up all night", "落ち着く": "to calm down", "基礎": "foundation", "応用": "application", "解く": "to solve", "本番": "the real thing (the actual performance/exam)", "慌てる": "to panic", "集中する": "to concentrate"}, "gramEn": {"〜たところで": {"exp": "Verb (ta-form) + ところで means \"even if … , (it's no use)\". It's almost always followed by a negative or futile outcome: \"Even if you panic, there's only so much you can do.\"", "ex": ["Even if you run now, you won't make it in time."]}, "〜ないことには": {"exp": "Verb (nai-form) + ことには + (negative result) means \"unless …, you can't …\". It stresses that the second clause won't happen if the precondition isn't met: \"Unless you calm down, you can't remember.\"", "ex": ["Unless you give it a try, you won't know whether you can do it."]}, "〜まい": {"exp": "① Negative will: \"I'll never …\" (しまい / するまい, 慌てるまい); ② Negative conjecture: \"probably won't …\" (あるまい). It's formal and literary; in conversation people say 〜ないつもり or 〜ないだろう instead.", "ex": ["I'll never make a mistake like that again.", "He probably won't come. No — surely he won't come."]}, "〜わけではない / 〜しかない": {"exp": "Review: 「上がるわけではない」 (it doesn't necessarily go up); 「集中するしかない」 (there's nothing to do but concentrate). This pair comes up often when talking about exam mindset.", "ex": ["Just because it's expensive doesn't mean it's good."]}}, "convEn": ["A: Is it still in time to study now? B: It's too late now — panicking at this point won't help.", "A: Shall I help? B: Unless you come, we can't even get started.", "A: I'll never be late again. B: Really? Even if you think \"I won't be late,\" you'll just end up oversleeping, right?"], "extEn": ["「〜たところで」(even if … , to no avail; followed by a negative) ≠「〜たら」(a plain conditional). The former carries a negative judgment of \"it's pointless.\"", "「〜ないことには」≈「〜なければ」, but it emphasizes the \"precondition\" more, and the second clause is usually negative or impossible.", "「〜まい」 has two meanings decided by context: with volitional verbs → negative resolve (するまい); with states / other people → negative conjecture (あるまい)."], "reflectEn": ["Write a sentence with 「〜たところで」 meaning \"even if I do it, it's no use.\"", "Write a sentence about a precondition using 「〜ないことには」.", "Write out 「決して諦めまい」 from memory, and explain what 「まい」 means here."]}, "27": {"themeEn": "Reading an Argumentative Essay — Does Effort Pay Off?", "goalsEn": ["Spotting the markers for \"claim · grounds · conclusion\"", "「だからといって〜ない」 that doesn't mean …", "「〜としても」 even if …"], "paraEn": ["People often say \"effort is always rewarded,\" but is that really true?", "Certainly, if you make an effort, your chances of succeeding go up.", "However, it doesn't follow that anyone can succeed as long as they just try hard.", "That's because results are determined not only by the person's own effort, but also by their environment and luck.", "That said, to conclude that effort is therefore meaningless is clearly a mistake.", "Even if you don't get the result you hoped for, the abilities you developed in the process of trying will never disappear.", "On the contrary, it is exactly those abilities that support your next challenge.", "In other words, the value of effort lies not in the result, but in how it makes a person grow."], "vocabEn": {"報われる": "to be rewarded", "確かに": "certainly (concession marker)", "高まる": "to rise", "本人": "the person himself / herself", "環境": "environment", "運": "luck", "左右される": "to be influenced / swayed", "明らかに": "clearly", "望む": "to wish for", "過程": "process", "支える": "to support", "価値": "value"}, "gramEn": {"確かに〜。しかし〜": {"exp": "The core rhythm of an argumentative essay: first 「確かに…」 (a concession—granting the other side a point), then 「しかし…」 (a reversal—stating your own view). Recognize this pair of signals and you've caught the essay's turn.", "ex": ["It's certainly convenient. However, there are problems too."]}, "なぜなら〜からである": {"exp": "A formal way to give grounds: 「なぜなら、〜からである / からだ」. It marks the \"grounds\" that follow a \"claim,\" so when you see it you know the author is explaining the reason.", "ex": ["I'm against it. That's because it's far too dangerous."]}, "だからといって〜ない": {"exp": "It picks up the previous sentence and denies a too-easy inference: \"but that doesn't mean ….\" 「だからといって、意味がないわけではない」. Very common in N2 reading.", "ex": ["It's expensive. But that doesn't necessarily mean it's good quality."]}, "〜としても / 〜にある": {"exp": "「〜としても」 = even if (hypothetically) …: 「得られなかったとしても」. 「Aは…点にある」 = A's (key / value) lies in …: a conclusion pattern.", "ex": ["Even if you fail, there is still something to be gained."]}}, "convEn": ["A: If I work hard, will my dream come true? B: Not necessarily, but the chances do go up.", "A: If you fail, it was all a waste, wasn't it? B: You can't really say that. You gain strength in the process.", "A: So what is this essay ultimately trying to say? B: It's that \"the value of effort lies in growth.\""], "extEn": ["The three-step method: ① find the \"claim\" (the author's opinion, often at the end with 「〜のである / 〜だろう / 〜と言える」); ② find the \"grounds\" (なぜなら・からである); ③ recognize \"concession → reversal\" (確かに…。しかし…).", "Demonstrative reference: その・この・それ point back to earlier text. What does this essay's 「その力こそ」 refer to? (= the abilities developed in the process of effort.) When you're lost, go back and find the referent.", "The three big soft denials: 〜わけではない (not necessarily), 〜とは限らない (not always), 〜とは言えない (you can't say) — the hallmark of an essay's cautious, measured tone."], "reflectEn": ["Locate the \"claim · grounds · conclusion\" in this essay and sum up each in one sentence in Chinese.", "Write a sentence using 「だからといって〜ない」.", "Write down what 「その力」 and 「次の挑戦」 refer to in this essay."]}, "28": {"themeEn": "Week 4 Wrap-Up — Looking Back on This Month", "goalsEn": ["Reusing N2 patterns within a single short passage", "Reading a tougher passage aloud with the kana covered", "Writing your own N2 reflection passage"], "paraEn": ["Looking back on this month, I've learned more than I would have believed possible.", "To be honest, N2 grammar is hard, and I have to admit there were many times I wanted to quit.", "But unless you keep going and try, you'll never know what you're really capable of.", "At first, far from memorizing the grammar, I couldn't even grasp the meaning of a sentence.", "Now, even reading an argumentative essay isn't all that painful anymore.", "Worrying about the exam results won't change my score.", "From now on, instead of agonizing over the goal of \"passing,\" I just want to treasure each day.", "I've made up my mind that I will never panic when the real exam comes.", "For the days that remain, I intend to believe in myself and run all the way to the finish."], "vocabEn": {"振り返る": "to look back", "驚く": "to be surprised", "正直に言えば": "to be honest", "何度も": "many times", "苦": "hardship (苦ではない = not painful)", "論説文": "argumentative essay", "悩む": "to worry / agonize", "走り抜く": "to run through to the end"}, "gramEn": {"① 〜ざるを得ない / 〜ないことには": {"exp": "Review: 「やめたくなったと言わざるを得ない」 (I can't help but admit …); 「続けてみないことには分からない」 (unless you keep trying, you won't know).", "ex": ["I can't help but admit it."]}, "② 〜どころか / 〜さえ": {"exp": "Review: 「覚えるどころか、意味さえ取れなかった」 = far from memorizing it, I couldn't even grasp the meaning. Two intensifiers used together for an escalating effect.", "ex": ["Far from replying, he won't even show his face."]}, "③ 〜たところで / 〜まい": {"exp": "Review: 「心配したところで、変わるわけではない」 (worrying won't help); 「焦るまい」 (I'll never panic).", "ex": ["No matter how much you regret it, the past won't come back."]}, "④ 〜をめぐって / 〜つもり": {"exp": "Review: 「目標をめぐって悩む」 (to agonize over a goal); 「走り抜くつもりだ」 (I intend to run all the way through).", "ex": ["We talked it over with our parents regarding my future path."]}}, "convEn": ["A: Isn't N2 grammar hard? B: It is — there were many times I wanted to quit.", "A: Have you gained confidence now? B: I can't say I have, but I'm not as scared as before.", "A: You'll probably get nervous on the actual exam. B: I've decided I won't panic. Let's go in calm."], "extEn": ["This week's list: 〜をめぐって・にあたって・次第 (three senses)・ざるを得ない・にすぎない・どころか・さえ/こそ・たところで・ないことには・まい・確かに…しかし・なぜなら…からである・だからといって〜ない・としても・the de-aru style・contracted forms.", "Reading strategy: read the questions first → find the \"claim sentence\" (at the end / after しかし) → use 「確かに / しかし / なぜなら / つまり」 to map the structure → track demonstrative references.", "Study method: cover the kana and read today's passage (which uses the de-aru style) aloud once — if you can read it smoothly, you've shown you can handle a tougher writing style."], "reflectEn": ["[This week's big assignment] Using this week's N2 patterns, write a 7–9 sentence reflection passage titled \"Looking back on this month.\"", "Cover the kana and read Day 27's argumentative essay aloud; compile your own \"readings / patterns mistakes notebook.\"", "Make one sentence each with 「〜ざるを得ない」, 「〜たところで」, and 「〜どころか」."]}, "29": {"themeEn": "Comprehensive Practice — My Little Story", "goalsEn": ["Mastering the four-part structure of a speech", "「〜ていただきたい」 and 「〜うちに」", "Bringing written grammar into your speaking"], "paraEn": ["Everyone, today I'd like you to listen to a little story of mine.", "A year ago, it took me several minutes just to read a single line of Japanese.", "I understood the meanings of the kanji, but I didn't know how to read them — that was the hardest part of all.", "But as I read aloud every day, little by little the words began to come out of my mouth naturally.", "Looking back now, I feel that each one of those steady little practice sessions has led to who I am today.", "What I want to tell you is just one thing: \"It doesn't have to be perfect. What matters is to keep going.\"", "Even a small step, as long as you don't stop, will surely take you far.", "So all of you too, please keep walking at your own pace."], "vocabEn": {"皆さん": "everyone", "物語": "story", "一行": "one line", "何分も": "many minutes", "つらさ": "hardship (つらい + さ)", "〜うちに": "while / during", "地道": "steady / down-to-earth", "つながる": "to connect / lead to", "完璧": "perfect", "止まる": "to stop", "遠く": "far away", "歩き続ける": "to keep walking"}, "gramEn": {"〜ていただきたい（と思います）": {"exp": "A humble request: 「聞いていただきたいと思います」 = I'd like to have you listen. Common when opening a speech or formal address. Politeness scale: 〜てください ＜ 〜ていただけますか ＜ 〜ていただきたい.", "ex": ["I'd like to take just a little of your time."]}, "〜うちに": {"exp": "Verb (dictionary form / ている) + うちに = while … (and a change happens unawares). 「読むうちに、出てくるようになった」 = as I kept reading, the words started coming out. Also 「若いうちに」, 「忘れないうちに」.", "ex": ["As we talked, we became friends."]}, "〜のに（逆接）/ たった〜": {"exp": "Review 「〜のに」 (even though …, yet …): 「意味は分かるのに、読み方が分からない」. 「たった一つ」 = only one, emphasizing how few.", "ex": ["Just a single \"thank you\" can save a person."]}, "スピーチの構成": {"exp": "The golden four parts: ① the hook (a greeting / question to grab attention); ② your own experience (a concrete, detailed story); ③ the one thing you most want to say (boiled down to a single line); ④ a message to the audience (a call or a blessing). This passage follows exactly that skeleton.", "ex": ["① Everyone … ② A year ago I … ③ What I want to tell you is … ④ So all of you too …"]}}, "convEn": ["A: Giving a speech is so nerve-racking. B: It doesn't have to be perfect. What matters is the feeling behind it.", "A: How did you get so good? B: As I kept doing it every day, I just naturally became able to.", "A: One last word. B: As long as you don't stop, you will surely go far."], "extEn": ["The four-part skeleton: ① the hook (greeting / pose a question); ② experience (tell a concrete, detailed story of your own); ③ the one thing you most want to say (compress the message into a single line); ④ the message (a call or blessing to the audience). Both Jobs and Murakami use this structure.", "「〜うちに」 (while / before you know it) vs. 「〜間に」 (during …, neutral). うちに often carries \"while you still can\": 明るいうちに帰る (go home while it's still light).", "The humble-request ladder: 〜てください ＜ 〜ていただけますか ＜ 〜ていただきたいのですが ＜ 〜ていただければ幸いです (the most polite, written)."], "reflectEn": ["[Big assignment] Following this model, write your own 3-minute mini-speech (be sure to include the four-part structure).", "Write a sentence about your own learning experience using 「〜うちに」.", "Practice the speech you wrote with the shadowing method until it's fluent, then record yourself and critique your intonation and pauses."]}, "30": {"themeEn": "Looking Back and the Next Step — Beyond This Point", "goalsEn": ["Reviewing the closing patterns", "「〜つもりはない」 to have no intention of …", "Seeing the exam as just a \"waypoint\" on the journey"], "paraEn": ["At last, this thirty-day journey of learning has reached its final day.", "Over this month, I've read, written, and read aloud so many passages.", "Looking back, I feel like a completely different person from who I was back at the N4 level.", "Of course, I'm still far from perfect, and there are mountains of words I don't know.", "But what matters more than the score itself is that I've built the habit of continuing to learn.", "The exam is no more than a single waypoint on a long journey.", "The real goal is to become able to express my own feelings freely in Japanese.", "So even after the exam is over, I have no intention of stopping these steps of mine.", "From tomorrow, another new step — let's keep walking, together."], "vocabEn": {"ついに": "finally", "旅": "journey", "最終日": "the final day", "迎える": "to welcome / reach", "別人": "a different person", "ほど遠い": "far from", "山ほど": "a mountain of", "習慣": "habit", "通過点": "a passing point / waypoint", "ゴール": "goal", "歩み": "steps / progress", "〜つもりはない": "to have no intention to"}, "gramEn": {"〜にすぎない（复习）": {"exp": "「通過点にすぎない」 = no more than a waypoint. A common expression for downplaying something that seems huge, used to adjust your mindset.", "ex": ["This is no more than a beginning."]}, "〜つもりはない": {"exp": "Verb (dictionary form) + つもりはない = to have no intention of …. Stronger in tone than 「〜ないつもり」. 「止めるつもりはない」.", "ex": ["I had no intention of lying."]}, "〜ようになる（复习）": {"exp": "The \"progress\" pattern running through the whole course: 「伝えられるようになる」 = to become able to convey. It echoes the start of the month (Day 2) and the end (Day 30).", "ex": ["I became able to state my own opinion."]}, "〜ましょう（呼びかけ）": {"exp": "Verb (masu-stem) + ましょう = let's …, often used to close a speech and draw closer to the audience. 「一緒に歩き続けましょう」.", "ex": ["Let's keep working hard together from now on too."]}}, "convEn": ["A: What will you do once the exam is over? B: Rest a little, then set my next goal.", "A: And if you don't pass N2…? B: I'll just take it on again. I have no intention of quitting.", "A: You worked so hard this year. B: Thank you. I'll keep walking from here on too."], "extEn": ["Time allocation: ① Language Knowledge (vocabulary · grammar) + Reading total 105 minutes — do the grammar questions quickly to leave plenty of time for reading; for each passage, read the questions first, then go back to the text for the answers.", "Reading: catch the \"claim sentence\" (usually at the end of the passage or after 「しかし」); use 「確かに / しかし / なぜなら / つまり」 to map the structure; always trace demonstratives (その · これ) back to their referents; you don't need to understand every word.", "Listening: at the start, pin down \"who · is going to do what\"; watch for turn / conclusion signals like 「でも · 実は · 結局 · やはり」; if you miss one question, let it go immediately so it doesn't drag down the next.", "Mindset and your strength: 「焦るまい」 (I won't panic). When you hit a word you don't know, guess its meaning from the kanji — this is exactly your greatest advantage as a native Chinese speaker. After the exam, keep reading aloud and speaking every day, so that N2 becomes the starting point for \"being able to speak,\" not the finish line."], "reflectEn": ["Write down your three biggest gains from these 30 days (in Chinese and/or Japanese).", "Using 「〜つもり」 and 「〜（よ）うと思う」, make a plan for continued study / speaking practice for \"after the exam.\"", "Write out the final line 「明日からも、また新しい一歩を」 from memory, and make it your motto."]}, "6": {"themeEn": "Plans Ahead — Intentions and Will", "goalsEn": ["Distinguish 〜予定 / 〜つもり / 〜（よ）うと思う", "〜までに (deadline) vs まで (duration)", "〜かどうか (whether or not)"], "paraEn": ["Starting next month, I'm going to push myself toward a new goal.", "Actually, I'm scheduled to take a Japanese exam this winter.", "With that in mind, I made a daily study plan.", "In the mornings I plan to memorize vocabulary, and at night to read passages aloud.", "On weekends, I intend to review what I learned that week.", "Before the exam, I want to review all the grammar I'm weak at.", "Whether or not I'll pass, I still don't know.", "But no matter how it turns out, I think the fact that I kept at it every day will surely become a source of confidence.", "In the future, I'd like to take that confidence and try working in Japan."], "vocabEn": {"来月": "next month", "目標": "goal", "〜に向かって": "toward, heading for", "実は": "actually, to tell the truth", "受ける": "to take (an exam), to receive", "予定": "schedule, plan (set arrangement)", "計画を立てる": "to make a plan", "単語": "vocabulary word", "音読する": "to read aloud", "復習する": "to review (↔ 予習 to prepare beforehand)", "苦手": "weak at, bad at (↔ 得意 good at)", "合格する": "to pass (an exam)", "結果": "result", "自信": "confidence", "将来": "future (one's own future)"}, "gramEn": {"〜予定です": {"exp": "Attach 予定です to a dictionary-form verb or 名詞＋の to express a plan that's already been set on a schedule. It feels more objective and definite than つもり, so it's used for fixed appointments and itineraries: 試験を受ける予定です = I'm scheduled to take the exam.", "ex": ["I'm scheduled to go on a business trip next week.", "The meeting is scheduled to start at three."]}, "〜（よ）うと思う": {"exp": "Take the volitional form (する→しよう, 覚える→覚えよう, 読む→読もう) and add と思う to say you've just decided to do something. Using 〜ようと思っている (with ている) shows it's an intention you've been holding for a while.", "ex": ["I think I'll go to bed early today.", "I'm planning to keep up with my Japanese."]}, "意志・计划 程度对比": {"exp": "These forms range from weak to strong commitment: 〜たい (want to, emotional) → 〜（よ）うと思う (plan to, just decided) → 〜つもり (intend to, fairly firm) → 〜予定 (scheduled, objective and set). Pick the form that matches how settled the plan is.", "ex": ["want to go → plan to go → intend to go → scheduled to go"]}, "〜までに vs まで": {"exp": "までに marks a deadline — a one-time action must happen by then (出す, 終わる, 着く). まで marks duration — an action continues up until that point (待つ, 寝る). Compare 五時までに来て (come by five) with 五時まで待つ (wait until five).", "ex": ["I'll hand in the report by Friday. (deadline)", "I'll walk to the station. (endpoint)"]}, "〜かどうか": {"exp": "This embeds a yes/no question into a larger sentence: 合格できるかどうか分からない = I don't know whether or not I can pass. It's typically followed by 分かる, 決める, 確認する, and the like.", "ex": ["I'll go ask whether or not (he's) coming."]}}, "convEn": ["A: I'm scheduled to take the exam this winter. B: Oh really? Good luck with it!", "A: What are you planning to do this weekend? B: I'm planning to do some review.", "A: By what time will you be done? B: I think I'll be done by five."], "extEn": ["実は is a conversational \"setup\" word that leads into the truth or something a bit hard to bring up — natural and very common.", "Learn them in pairs to remember them better: 予習/復習, 得意/苦手, 予定/結果.", "If 〜かどうか involves a question word (who/when), just use 〜か instead: いつ来るか分からない (I don't know when he's coming)."], "reflectEn": ["Write one sentence with 〜予定です and one with 〜（よ）うと思っています about your own pre-exam plans.", "Make two sentences using まで / までに and feel the difference between \"duration\" and \"deadline.\"", "Write from memory the sentence about \"keeping at it becoming confidence.\""]}, "7": {"themeEn": "Week One Wrap-Up — Me Right Now", "goalsEn": ["Reuse all of this week's grammar in a single short essay", "See how grammar naturally combines into paragraphs", "Model your own self-essay on it"], "paraEn": ["I'm a student who came from China, and right now I'm studying Japanese.", "Every day, I try to sit down at my desk at a set time.", "After I get up in the morning, I first read aloud the words I learned the day before.", "Lately, I've become able to catch Japanese that's a little faster than before.", "There's a quiet park in the town where I live, and I often read aloud there while taking a walk.", "I haven't traveled to Japan yet, but someday I definitely want to go.", "Since I'm scheduled to take the exam this winter, I intend to review my weak spots before then.", "Passing the exam matters too, but my real goal is to become able to express my own thoughts freely.", "I plan to keep working hard, one step at a time, from here on out."], "vocabEn": {"決まる": "to be decided / fixed (intransitive, ↔ 決める transitive)", "昨日": "yesterday", "最近": "recently, lately", "必ず": "surely, without fail", "大切": "important, precious", "自由に": "freely", "一歩ずつ": "step by step"}, "gramEn": {"① 〜ています / 〜ようにしている": {"exp": "Review: 〜ています expresses a habit or ongoing state, while 〜ようにしている means you deliberately make a point of keeping up a habit. Example: 決まった時間に机に向かうようにしています (I make a point of sitting at my desk at a set time).", "ex": ["I make a point of eating vegetables every day."]}, "② 〜てから / 〜ながら": {"exp": "Review: 〜てから means do A first, then B; 〜ながら means doing B while A. Examples: 起きてから読む (read after getting up), 散歩しながら音読する (read aloud while walking).", "ex": ["After eating, I watch TV while brushing my teeth."]}, "③ 〜ようになった": {"exp": "Review: \"became able to...,\" stressing progress. Example: 聞き取れるようになりました (I became able to understand by ear). Note the contrast with 〜ようにする — a natural change versus a deliberate effort.", "ex": ["I became able to read kanji."]}, "④ 〜たことがある": {"exp": "Review: an experience of having (or never having) done something. Example: 旅行に行ったことはまだありません (I haven't traveled there yet).", "ex": ["Have you ever eaten sashimi?"]}, "⑤ 予定 / つもり / 〜（よ）うと思う": {"exp": "Review: use 予定 for an objective, scheduled plan, and つもり or 〜（よ）うと思う for a subjective intention. Examples: 受ける予定 (scheduled to take), 復習するつもり (intend to review), 頑張っていこうと思う (plan to keep trying).", "ex": ["I'm scheduled to go home this summer, but if it's too much I think I'll drop it."]}}, "convEn": ["A: How do you study every day? B: After I get up, I make a point of reading aloud.", "A: Have you ever been to Japan? B: Not yet, but I'm scheduled to go this winter.", "A: What's your goal? B: To become able to speak freely."], "extEn": ["This week's grammar checklist: は/が・です/ます・〜ています・〜てから・〜のは…です・〜たい・〜ために・〜ようになる・〜たり〜たり・〜ながら・〜と思う・〜なければならない・〜たほうがいい・potential form・〜つもり・existence sentences・position words・〜たことがある・〜とき・〜予定・〜までに・〜かどうか.", "Pronunciation traps to revisit: 通[つう]じる / 通[とお]して, 十分[じゅっぷん], 図書館[としょかん], 一生[いっしょう], 一歩[いっぽ] — geminate (small っ) and long vowels are exactly what native Chinese speakers tend to drop.", "Study tip: today, try writing a paragraph about \"the current me\" (5–8 sentences) without looking at the original, then read it aloud, record yourself, and compare with the audio."], "reflectEn": ["[This week's big assignment] Following this model essay, write a 5–8 sentence \"私の今\" (Me Now), using at least 5 of this week's grammar points.", "Type your essay using the \"night reflection\" input mode and check whether your kana are correct.", "Record yourself reading it aloud, compare with the site's audio, and mark the words you pronounced inaccurately."]}, "8": {"themeEn": "Cause and Reason — Why I Study Japanese", "goalsEn": ["Politeness level of 〜ので vs 〜から", "〜おかげで (positive) and 〜せいで (negative)", "〜というのは…ことだ to give a definition"], "paraEn": ["There are several reasons I started studying Japanese.", "The biggest reason is that I love Japanese culture.", "As a child, I watched a lot of anime, so I naturally came to take an interest in Japanese.", "Also, since I want to work in Japan in the future, I believe language ability is essential.", "At first, thanks to being able to read kanji, I thought studying would be easy.", "However, because I didn't know the readings, it was harder than I'd expected.", "Even so, thanks to the help of my teachers and friends, I've gradually gained confidence.", "Learning a language is also a way of understanding how the people of that country think.", "That is precisely why I want to keep facing Japanese seriously from here on."], "vocabEn": {"理由": "reason", "一番": "the most, number one", "文化": "culture", "興味を持つ": "to take an interest (interest is marked with に)", "必要": "necessary", "楽": "easy, comfortable (≠ 楽しい fun)", "苦労する": "to struggle, to have a hard time", "助ける": "to help, to rescue", "自信がつく": "to gain confidence", "考え方": "way of thinking", "だからこそ": "that is precisely why", "真剣に": "seriously, in earnest", "向き合う": "to face, to confront"}, "gramEn": {"〜ので vs 〜から": {"exp": "Both give a reason. から is subjective and stronger, used when explaining your own judgment or giving commands; ので is more objective and softer, sounding more polite for requests and explanations. Connection: な-adjectives and nouns take なので.", "ex": ["I have a headache, so may I head home early? (soft request → ので)", "It's dangerous, so don't touch it. (strong tone → から)"]}, "〜ため（に）": {"exp": "〜ため can express a cause (\"because of\") or a purpose (\"in order to\"). A dictionary-form verb + ため reads as purpose; a past or stative form + ため reads as cause. Here 働きたいため is a cause.", "ex": ["Due to an accident, the train is stopped. (cause)", "I exercise for the sake of my health. (purpose)"]}, "〜おかげで / 〜せいで": {"exp": "Both mean \"because of,\" but they carry opposite feelings: おかげで = thanks to (a good outcome, gratitude), せいで = blaming (a bad outcome, fault).", "ex": ["Thanks to my teacher, I was able to pass.", "Because I overslept, I missed the train."]}, "〜というのは…（という）ことだ": {"exp": "Use this to define a concept or spell out what it means: Aというのは、Bということだ = \"What A means is B / A is to say B.\"", "ex": ["Keigo (honorific language) is, in essence, language that shows respect for the other person."]}}, "convEn": ["A: Why did you start learning Japanese? B: Because I used to love anime.", "A: It's nice that you can read kanji. B: I get the meaning, it's the readings that get me...", "A: So you passed! B: Yes — thanks to my teacher."], "extEn": ["から (subjective, strong) vs ので (objective, soft): when calling in sick, giving an excuse, or making a polite request, ので almost always sounds more appropriate.", "おかげで (gratitude, positive) vs せいで (blame, negative): for a neutral outcome you can use 〜ことで or 〜ため instead.", "Same kanji, different readings: 楽[らく] (easy/comfortable) ≠ 楽[たの]しい (fun). One more two-reading kanji — watch for it."], "reflectEn": ["Write one sentence with 〜ので and one with 〜から, and feel the difference in politeness.", "Make one sentence each with おかげで / せいで (one good thing, one bad thing).", "Write from memory the sentence about \"learning a language is understanding how a people think.\""]}, "9": {"themeEn": "Passive and Causative — Things Done to You, Things You're Made to Do", "goalsEn": ["Forming the passive and the causative", "Causative-passive 〜（さ）せられる for being made to do something", "The adversative passive for being negatively affected"], "paraEn": ["These days, Japanese is being studied by many people around the world.", "Through anime and games, Japanese culture has been spread across the world.", "I, too, started learning Japanese because a friend recommended it to me.", "As a child, I was made to write kanji every day by my mother, and I hated it.", "But now, the kanji I was forced to memorize back then are really useful.", "Last week, I was asked a question by the teacher in class and couldn't answer well.", "I made a mistake in front of everyone and felt a little embarrassed.", "Still, I think it's precisely by having our mistakes corrected that people can grow.", "From now on, I want to speak up more on my own initiative."], "vocabEn": {"世界中": "all over the world", "広める": "to spread (transitive, ↔ 広まる intransitive)", "勧める": "to recommend, to urge", "母": "(my own) mother [humble]", "嫌": "unpleasant, disagreeable, reluctant", "役に立つ": "to be useful, to come in handy", "質問する": "to ask a question", "間違える": "to make a mistake", "恥ずかしい": "embarrassed, shy", "直す": "to fix, to correct (transitive, ↔ 直る intransitive)", "成長する": "to grow", "自分から": "on one's own initiative"}, "gramEn": {"受身形（〜られる）": {"exp": "The passive (\"to be done to\"). Group I: shift the final sound to the あ-row and add れる (書く→書かれる). Group II: add られる (食べる→食べられる). する→される, 来る→来られる. The doer is marked with に: 友だちに勧められる (recommended by a friend).", "ex": ["This book is read by many people.", "I was praised by the teacher."]}, "使役形（〜（さ）せる）": {"exp": "The causative (\"make/let someone do\"). Group I: あ-row + せる (書く→書かせる). Group II: + させる (覚える→覚えさせる). する→させる. It means make, let, or allow. The person made to act is marked with に (for transitive verbs) or を (for intransitive verbs).", "ex": ["Mom made my little brother tidy up his room."]}, "使役受身（〜（さ）せられる／〜される）": {"exp": "The causative-passive: being made to do something (against your will). In speech, Group I verbs usually contract: 書かせられる→書かされる; compare 覚えさせられる. So 漢字を書かされた = I was forced to write kanji. Note that す-ending verbs like 話す don't contract: 話させられる.", "ex": ["As a child, I was made to take piano lessons."]}, "迷惑の受身": {"exp": "The adversative (\"suffering\") passive: the subject is troubled or harmed by something, even when there's no \"being done to\" sense in English. Examples: 雨に降られる (get rained on, unluckily), 子どもに泣かれる (be troubled by a child crying).", "ex": ["Someone stepped on my foot on the train."]}}, "convEn": ["A: Did the teacher praise you? B: No — on the contrary, I got told off.", "A: As a kid, what were you made to learn? B: I was made to take calligraphy.", "A: Speaking in front of people is nerve-wracking, isn't it? B: Yeah, but once you get used to it, it's no big deal."], "extEn": ["The single form 食べられる has three meanings: potential (can eat), passive (be eaten), and honorific (you eat). Tell them apart by the particles and context — a high-frequency N3/N2 test point.", "Causative-passive contraction: for Group I verbs, 〜せられる→〜される (書かされる, 飲まされる) is common in speech; but verbs ending in す (話す, 貸す) don't contract.", "Doer particle: the passive uses に (〜に＋られる); for large-scale or creative acts you can use によって (この絵はピカソによって描かれた — this painting was painted by Picasso)."], "reflectEn": ["Turn 書く into passive (書かれる), causative (書かせる), and causative-passive (書かされる), and make one sentence with each.", "Write one sentence with 〜ことで meaning \"by doing X, you gain Y.\"", "Write from memory the sentence about \"growing by having mistakes corrected.\""]}, "10": {"themeEn": "Conditionals — と, たら, ば, なら", "goalsEn": ["と for inevitable results, たら for all-purpose suppositions", "ば for general conditions, なら for picking up a premise", "Telling the four apart when giving advice"], "paraEn": ["If you want to get good at Japanese, the important thing is to keep at it every day, even just a little.", "In my experience, when you read aloud, you remember things remarkably well.", "If you come across a new word, write it down in your notebook right away.", "If you have the time, it's good to try making your own sentences using that word.", "If there's something you don't understand, you're better off asking the teacher without holding back.", "If you practice every day, you should definitely feel a change after six months.", "Conversely, if you only study once every three days, it just won't stick.", "In other words, what matters is continuing, more than the amount.", "There's no need to rush, so let's move forward at our own pace."], "vocabEn": {"続ける": "to continue, to keep up (transitive, ↔ 続く intransitive)", "不思議": "mysterious, strange", "出会う": "to come across, to encounter", "〜ておく": "to do in advance (書いておく = write it ahead of time)", "遠慮する": "to hold back, to be reserved", "半年": "half a year", "変化": "change", "逆に": "conversely, on the contrary", "身につく": "to master, to acquire (intransitive, ↔ 身につける transitive)", "量": "quantity, amount", "焦る": "to be impatient, to feel rushed", "ペース": "pace"}, "gramEn": {"〜と": {"exp": "Once the first clause holds, the second clause inevitably or naturally follows — used for general truths, mechanical operations, and habits. The second clause can't be a volitional statement, command, or request. Examples: 読むと覚えられる (when you read it, you remember it), 春になると咲く (when spring comes, they bloom).", "ex": ["When you push this button, the door opens."]}, "〜たら": {"exp": "The most versatile conditional: it covers suppositions (\"if\") and \"after\" a definite future event. It's the go-to in casual speech. Examples: 出会ったら書く (if/when you come across it, write it down), 家に着いたら電話する (call me when you get home).", "ex": ["When you get to the station, please call me.", "If it's cheap, I'll buy it."]}, "〜ば": {"exp": "A general or hypothetical condition, common in proverbs and often paired with stative verbs and adjectives. Examples: 時間があれば (if you have time), 練習していれば (if you keep practicing). Note 〜ば〜ほど = \"the more... the more...\"", "ex": ["The more you practice, the better you get."]}, "〜なら": {"exp": "Picks up something the other person just said or a given premise: \"if it's the case that...\" / \"as for...\" Examples: 上手になりたいなら (if you want to get good), 日本へ行くなら新幹線がいい (if you're going to Japan, the bullet train is the way). Often used to give advice.", "ex": ["If you're buying a computer, this shop is cheap, you know."]}}, "convEn": ["A: How can I get good at it? B: If you keep at it every day, you'll definitely improve.", "A: If I'm going to Japan, when is good? B: If you want to see the cherry blossoms, April is good.", "A: What does this word mean? B: If you look it up in a dictionary, you'll know right away."], "extEn": ["と = inevitable/constant (can't take volition or commands); たら = all-purpose supposition / \"after\" (first choice in speech); ば = general condition / proverbs; なら = picks up the other person's topic, sets a premise.", "なら is the special one: it picks up what the other person just said. 日本へ行くなら… ((Since you say) you're going to Japan...) — first acknowledge, then advise.", "Going further: 〜ば〜ほど (the more... the more...), and たら can also signal \"and then I discovered\": 窓を開けたら、雪だった (I opened the window and found it was snowing)."], "reflectEn": ["Write one piece of advice using たら and one using なら, and feel the difference.", "Write one sentence with 〜と describing a phenomenon where \"doing X inevitably leads to Y.\"", "Write from memory the sentence about \"amount mattering less than continuing\" (つまり…)."]}};
